-- 141: Michelin-chef pass — COMPLETE, rebuilt the efficient way (Richard, 17.7.2026:
-- "znova postav ale ovela lepsie nech je to efektivnejsie").
--
-- What changed vs. the old batches (db/64/66/72/91/92):
--   * ONE migration covers every library recipe (all 173 titles + 10 promoted community
--     recipes) instead of hand-curated category batches spread over days.
--   * Updates key on (title + created_by is null) — so they hit the library copy in EVERY
--     kitchen at once, not a single kitchen's row ids like the old per-id batches did.
--   * Every update is guarded with "and coalesce(chef_notes,'') = ''" — idempotent and
--     non-destructive: rows already enriched by the old batches keep their text untouched.
--   * Scope question resolved by reality: the pilot is Burrito Bandito (Mexican) and the
--     first sales target is Nooch (Asian) — Asian recipes are fully in scope now; the old
--     batches' Asian exclusions are filled in here.
--   * Part 1 promotes the community recipes users shared with Sautero (shared_with_sautero =
--     true, 10 unique titles as of 17.7.) into the library: one copy per kitchen, common
--     chefos_master_id, created_by null — exactly like the original 173.
--
-- Fields filled per recipe: equipment, chef_notes, storage, shelf_life, plating_suggestions
-- (the 5 empty slots of the 20-field format — ingredients/method were already professional).
-- Professional-standard suggestions, not verified against this kitchen's exact practice.

-- ============ Part 1: promote shared community recipes into the library ============
do $promote$
declare
  src record;
  k record;
  new_master uuid;
begin
  for src in
    select distinct on (title) * from recipes
    where shared_with_sautero and created_by is not null
    order by title, created_at
  loop
    if exists (select 1 from recipes where created_by is null and title = src.title) then
      continue;
    end if;
    new_master := gen_random_uuid();
    for k in select id from kitchens loop
      insert into recipes (kitchen_id, title, subtitle, description, category, station, cuisine,
        difficulty, yield_text, prep_time_active, prep_time_passive, equipment, chef_notes,
        storage, shelf_life, variations, scaling_notes, plating_suggestions, cross_references,
        allergens, tags, image_url, sections, is_custom, chefos_master_id, is_personal)
      values (k.id, src.title, src.subtitle, src.description,
        coalesce(src.category, 'Community'), src.station, src.cuisine, src.difficulty,
        src.yield_text, src.prep_time_active, src.prep_time_passive, src.equipment,
        src.chef_notes, src.storage, src.shelf_life, src.variations, src.scaling_notes,
        src.plating_suggestions, src.cross_references, src.allergens, src.tags, src.image_url,
        src.sections, src.is_custom, new_master, false);
    end loop;
  end loop;
end $promote$;

-- ============ Part 2: fill the 5 professional fields wherever they're empty ============
update recipes set equipment = 'Small pot; brush for service; bottle', chef_notes = 'Soy, mirin, sake and dashi gently reduced — the alcohol burned off, the edge rounded. It should coat the brush thinly; over-reduction makes it salty paint.', storage = 'Refrigerated, sealed, 1 month.', shelf_life = '1 month refrigerated.', plating_suggestions = 'Component — brushed on nigiri in one stroke at the pass; the soft sheen it leaves is the finished look of Edomae service.' where created_by is null and title = 'Nikiri Shoyu' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Whisk or blender for the dressing; salad spinner', chef_notes = 'Dress at the very last moment — butterhead wilts fast under acid and oil. Keep spare croutons dry until plating so they stay crisp.', storage = 'Dijon dressing keeps refrigerated, airtight, up to 5 days — re-whisk before use as it will separate.', shelf_life = 'Dressing: 5 days refrigerated. Assembled salad: serve immediately, do not hold.', plating_suggestions = 'Build height with the torn leaves rather than laying them flat; scatter croutons last so they stay visible and crisp, dressing pooled lightly at the base of the plate.' where created_by is null and title = 'Butterhead Lettuce, Wild Herbs, Croutons, Dijon Vinaigrette' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Silicone mat; offset spatula; oven; curved form for shaping', chef_notes = 'The seeds want an even single layer — clumps burn while gaps stay pale. Shape in the brief hot window; black-and-white sesame mixed reads more deliberate than either alone.', storage = 'Airtight, room temperature, 3-4 days away from humidity.', shelf_life = '3-4 days airtight.', plating_suggestions = 'Component — a shard planted at angle over Asian-leaning desserts; the toasted-seed aroma should reach the guest before the spoon does.' where created_by is null and title = 'Sesame Tuile' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Sharp knife (hand-chopped, never blended); bowl; jar', chef_notes = 'Chop, don''t process — blended chimichurri turns to muddy pesto. Make it at least an hour ahead so the oregano and garlic bloom in the vinegar, but same-day; the green fades overnight.', storage = 'Refrigerated, surface covered with oil, 3 days — best day one.', shelf_life = '3 days refrigerated; brightest first 24 h.', plating_suggestions = 'Spoon loosely over grilled meat at the table, some on, some beside — it should look scattered by appetite, not arranged.' where created_by is null and title = 'Chimichurri' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Box grater or food processor; muslin or clean towel for squeezing', chef_notes = 'Squeeze the grated beet almost dry — wet filling steams the wrapper open and bleeds through. Season more assertively than tastes right raw; the wrapper mutes everything.', storage = 'Filling keeps refrigerated, airtight, up to 2 days; filled gyoza freeze up to 2 months on trays before bagging.', shelf_life = 'Filling: 2 days refrigerated. Filled: cook fresh same day or straight from frozen.', plating_suggestions = 'Component recipe — the magenta interior is the reveal; serve gyoza seared-side up so the first cut shows the colour.' where created_by is null and title = 'Beetroot Gyoza Filling' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Deep pot or fryer with thermometer; piping bag if shaped; rack', chef_notes = 'These want a slightly lower fry than Western doughnuts — the mochi-style chew develops as they cook through slowly. Roll in sugar warm, fill cold.', storage = 'Fried: hours, not days. Dough/batter: refrigerated per recipe, typically 24 h.', shelf_life = 'Serve within 2-3 hours of frying.', plating_suggestions = 'Stack in threes, dusted; if filled, let a little filling show at the piping hole — appetite is visual.' where created_by is null and title = 'Japanese Šišky (Doughnuts)' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Baguette perforated tray or couche (linen proofing cloth); lame or razor blade for scoring; steam source in the oven (spray bottle or ice cubes in a tray)', chef_notes = 'Poolish should be bubbly and just starting to collapse at the centre before mixing -- under-ripe poolish gives less flavour, over-ripe turns sour and weakens the dough. Score at a shallow angle (20-30 degrees) in one confident motion; hesitant scoring tears the crust instead of opening it cleanly.', storage = 'Best eaten within a few hours of baking -- no lean bread like this holds well. If needed, wrap in paper (not plastic, which softens the crust) at room temperature for same-day service.', shelf_life = 'Crust noticeably softens within 4-6 hours; for longer storage, slice and freeze rather than holding at room temperature.', plating_suggestions = 'Let it cool at least 20 minutes before cutting -- slicing hot traps steam inside and gums the crumb.' where created_by is null and title = 'French Baguette' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Crisp nori halves; bowl of tezu; nothing else — this is a hands dish', chef_notes = 'The cone is rolled in seconds and eaten in fewer — nori starts softening on contact with rice immediately. In service, temaki is handed directly, never plated and left.', storage = 'None. A temaki that waited is a different, sadder dish.', shelf_life = 'Eaten within 1-2 minutes of rolling.', plating_suggestions = 'Hand it across the pass point-down in a holder or directly to the guest; the crackle of the first bite is the entire quality metric.' where created_by is null and title = 'Temaki (Hand Roll) — Technique' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Flat griddle or heavy non-stick pan; ring moulds optional for uniform rounds', chef_notes = 'The batter should fall in ribbons — rest it 15 minutes so the honey hydrates the flour and the surface browns evenly to that signature mirror finish. Flip only once, when bubbles just break the surface.', storage = 'Cooled pancakes keep wrapped at room temperature 1 day or frozen up to 1 month, layered with parchment.', shelf_life = 'Filled dorayaki: same day. Unfilled pancakes: 1 day room temp / 1 month frozen.', plating_suggestions = 'Sandwich generously with anko so the filling bulges slightly at the seam; serve slightly warm — 10 seconds of steam brings frozen ones back to fresh.' where created_by is null and title = 'Dorayaki Pancakes' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Wide pot with lid for popping; large bowl for tossing; sieve for dusting', chef_notes = 'Toss the hot popcorn with the matcha sugar in stages — all at once and it clumps on the first handful. A pinch of salt makes the matcha taste greener.', storage = 'Airtight at room temperature 2 days before the crunch fades.', shelf_life = '48 hours airtight.', plating_suggestions = 'Component/garnish — a few pieces add irreverence and crunch to a plated matcha dessert; also works as a pre-dessert snack in a paper cone.' where created_by is null and title = 'Green Tea Popcorn' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Food processor; pan for the duxelles stage; cling film for logs', chef_notes = 'Cook the mushrooms fully dry first — any moisture and the butter goes rancid in days instead of weeks. Dried porcini powder deepens it beyond fresh mushrooms alone.', storage = 'Rolled logs: refrigerated 10 days, frozen 3 months.', shelf_life = '10 days refrigerated / 3 months frozen.', plating_suggestions = 'Component — melt over grilled meat or steamed greens, or finish a pan sauce with a slice; it should arrive still melting.' where created_by is null and title = 'Mushroom Butter' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Ice cream machine; thermometer; fine sieve; real vanilla pods', chef_notes = 'The benchmark dessert — cook the anglaise to 84°C, mature the base overnight (genuinely improves body), and use pods you''d be proud to show. Speckle is the signature of the real thing.', storage = 'Base: 2 days refrigerated. Churned: -18°C, best within 2 weeks.', shelf_life = 'Base 48 h; churned 2 weeks at peak.', plating_suggestions = 'A perfect quenelle can carry a plate alone; on warm desserts, seat it on crumble so it melts slower and stays put.' where created_by is null and title = 'Vanilla Ice Cream' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Fine sieve; heavy-bottomed pot', chef_notes = 'Cook the sago in plenty of water and pull it while a few white centres remain — it finishes translucent as it sits in the warm coconut base. Rinse well to shed surface starch or the pudding turns gluey.', storage = 'Keeps refrigerated, covered, up to 3 days; the sago firms as it chills — loosen with a splash of coconut milk before serving.', shelf_life = '3 days refrigerated. Do not freeze — sago pearls turn rubbery.', plating_suggestions = 'Serve in glass so the pearls show; top with mango or palm-sugar syrup in a thin, deliberate layer rather than stirred through.' where created_by is null and title = 'Coconut Sago Pudding' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Mixing bowl; fork or potato masher (not a food processor — keeps texture)', chef_notes = 'Make close to service — even with lime juice, avocado starts browning within an hour. Taste for salt twice: once after mashing, again after folding in the other ingredients, since they dilute the seasoning.', storage = 'Press plastic wrap directly onto the surface (no air gaps) and refrigerate — this slows browning more than the lime juice does.', shelf_life = 'Best within 4-6 hours refrigerated, surface-wrapped. Visible browning isn''t unsafe, just less appealing — trim and re-taste before serving.', plating_suggestions = 'Leave it rustic and chunky rather than smoothing it out — the texture is the point; a lime wedge alongside signals freshness.' where created_by is null and title = 'Classic Guacamole' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Small pot; fine strainer; bottles for service', chef_notes = 'Tare is the seasoning, broth is the body — never salt the broth itself. 30-45 ml of tare per bowl, laid in the bowl BEFORE the broth pours in; taste your combined result weekly and adjust the tare, not the pot.', storage = 'Refrigerated, sealed, 1 month — it''s mostly soy and aromatics.', shelf_life = '1 month refrigerated.', plating_suggestions = 'Component — the bowl-bottom foundation; a correctly-tared ramen needs no table seasoning, which is the standard to hold.' where created_by is null and title = 'Ramen Tare (Shoyu Base)' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Food processor or stand mixer; cling film for rolling logs; sharp knife', chef_notes = 'The recipe is the ritual: every one of the many ingredients matters, and 24 h maturation before use is when they marry. Roll, chill, slice — never spoon it soft.', storage = 'Rolled logs: refrigerated 2 weeks, frozen 3 months; slice from frozen as needed.', shelf_life = '14 days refrigerated / 3 months frozen.', plating_suggestions = 'One thick disc melting over a rested steak at the pass — it should be half-melted when it reaches the guest, aroma rising.' where created_by is null and title = 'Café de Paris Butter' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Sharp chef''s knife (no food processor); chilled mixing bowl; ring mould (optional)', chef_notes = 'Use only beef rated for raw consumption by your supplier, hand-cut same day of service. Keep the bowl, knife, and beef cold throughout — warmth is the main enemy of both texture and food safety here.', storage = 'Prepare to order — this is not a hold item. Raw fillet trim keeps refrigerated (0-2°C) up to the supplier''s use-by date, but once cut and mixed, serve within the hour.', shelf_life = 'Same-day prep only; discard any unserved mixed tartare at the end of service.', plating_suggestions = 'Classic quenelle or ring-moulded disc, raw yolk nested on top, toast points fanned alongside — keep the garnish minimal so the beef stays the focus.' where created_by is null and title = 'Steak Tartare, Classic Preparation' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Rolling pin or pasta machine; round cutter; scale', chef_notes = 'Hot-water dough is what gives the wrapper its chew and pleatability. Roll centre-thick, edge-thin — the fold doubles the edge. Six to eight pleats, all leaning one way; consistency is the craft.', storage = 'Dough: wrapped, room temp 2 h or refrigerated 24 h. Wrappers: dusted, stacked, refrigerated 2 days.', shelf_life = 'Wrappers 2 days refrigerated / 1 month frozen in stacks.', plating_suggestions = 'Component technique — uniform pleats lined up in the pan photograph the kitchen''s standards better than any garnish.' where created_by is null and title = 'Gyoza Dough & Folding Technique' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Banneton (proofing basket) or a well-floured bowl lined with a tea towel; Dutch oven or baking stone with steam for the bake', chef_notes = 'Starter must pass the float test (a spoonful floats in water) before mixing, not just "looks bubbly" -- an unripe starter gives a dense, gummy crumb no amount of extra proofing will fix. Bulk-ferment by feel and volume increase (about 50%), not by the clock -- timing shifts a lot with kitchen temperature.', storage = 'Store cut-side down on a wooden board or in a paper bag at room temperature -- plastic traps moisture and turns the crust soft/chewy within hours.', shelf_life = '2-3 days at room temperature (sourdough keeps longer than commercial-yeast bread thanks to the acidity); freezes well sliced.', plating_suggestions = 'Full cool-down (at least 1 hour) before slicing is non-negotiable here -- the crumb is still setting internally right after baking.' where created_by is null and title = 'Sourdough Country Loaf' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Heavy pot; sharp knife (the cuts show); ladle', chef_notes = 'Vegetables go in by cooking time, not all at once — every element should finish tender at the same moment. The parmesan rind simmered in is the quiet secret.', storage = 'Improves overnight; refrigerated 4 days. Pasta or rice added per service only.', shelf_life = '4 days refrigerated / 3 months frozen (without pasta).', plating_suggestions = 'Rustic bowl, a spoon of pesto or good oil on top, parmesan at the table — the even dice of the vegetables is where the kitchen''s pride shows.' where created_by is null and title = 'Minestrone' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Blender or mortar; wide pan for frying the paste; jar', chef_notes = 'The paste is only half-made when blended — frying it in oil until the fat separates and it smells cooked is the other half. Do that step now or every dish made from it tastes raw.', storage = 'Fried paste, oil-capped, refrigerated 2 weeks; frozen in portions 3 months.', shelf_life = '14 days refrigerated / 3 months frozen.', plating_suggestions = 'Component — the engine of the house curries; a small extra spoon fried and thinned makes an instant finishing drizzle.' where created_by is null and title = 'Kari Pasta (Spiced Curry Paste)' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Ring moulds or tin; blender for the coulis; fine sieve', chef_notes = 'Bergamot is loud — infuse the zest, taste, and stop before it reads as perfume. Macerate the strawberries with a little sugar so they lacquer themselves in their own syrup.', storage = 'Cheesecake base holds refrigerated 3 days; strawberries dressed max 4 hours ahead.', shelf_life = '3 days refrigerated (base); assembled plate: serve immediately.', plating_suggestions = 'A clean disc or quenelle of cheesecake, strawberries glossy beside it, bergamot syrup dotted — keep whites and reds separated on the plate so both stay vivid.' where created_by is null and title = 'Cheesecake, Bergamot & Strawberries' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Grill or ridged grill pan; blender for the dressing', chef_notes = 'Char hard and fast at the end rather than cooking longer — the octopus should already be tender from its initial cook, so grilling here is for colour and smoke, not doneness.', storage = 'Sherry dressing keeps refrigerated, airtight, up to 1 week. Cooked octopus (pre-grill) keeps refrigerated up to 3 days.', shelf_life = 'Dressing: 7 days refrigerated. Plated dish: serve immediately.', plating_suggestions = 'Slice the octopus on a slight bias for maximum surface area, fan over the dressed vegetables, and finish glossy with a final spoon of dressing rather than a dry plate.' where created_by is null and title = 'Grilled Octopus, Peppers, Garlic, Sherry' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Ungreased chiffon tin (critical); stand or hand mixer; fine sieve', chef_notes = 'Never grease the tin — chiffon climbs the walls and an oiled tin collapses the crumb. Cool fully inverted. Fresh pandan extract beats bottled essence by a mile; blend leaves with a little water and squeeze.', storage = 'Keeps wrapped at room temperature 2 days, refrigerated 4 days, or frozen in wedges 1 month.', shelf_life = '2 days room temp / 4 days refrigerated / 1 month frozen.', plating_suggestions = 'Tall wedges to show the airy crumb; pair with salted coconut cream — the green needs nothing more than white beside it.' where created_by is null and title = 'Pandan Chiffon Cake' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Blender or whisk + a steady hand for the oil stream; a stand mixer with whisk attachment works well for larger batches', chef_notes = 'The emulsion lives or dies on how slowly you start adding the oil — go drop by drop at first, only speeding up once it visibly thickens. If it splits, whisking a fresh yolk in separately and slowly re-incorporating the split mixture will usually rescue it.', storage = 'Keeps refrigerated, airtight, up to 5 days — raw-egg-based, don''t push it further.', shelf_life = '5 days refrigerated.', plating_suggestions = 'A small quenelle or a thin ribboned line reads more considered than a dollop — black garlic''s colour is striking enough not to need much else around it.' where created_by is null and title = 'Black Garlic Aioli' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Steamer or pot for boiling; skewers', chef_notes = 'Knead the dough with just-boiled water in stages — it should feel like an earlobe, the classic test. Dust with kinako only at service; it drinks moisture and cakes within the hour.', storage = 'Dango harden quickly — hold at room temperature, covered with a damp cloth, and serve within 4-6 hours.', shelf_life = 'Same day only; refrigeration ruins the texture irreversibly.', plating_suggestions = 'Three to a skewer, generously dusted, with a pool of kuromitsu or soya caramel on the side for dipping rather than poured over.' where created_by is null and title = 'Kinako Dango (Sweet Soy-Bean Rice Dumplings)' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Pasta machine or rolling pin; scale (hydration is everything); rest time', chef_notes = 'Weigh, don''t cup — noodle dough lives or dies on hydration percentage. Rest a minimum 30 minutes before rolling; an unrested dough fights back and tears.', storage = 'Dough ball: refrigerated, wrapped tight, 24 h. Cut noodles: dusted and nested, refrigerated 2 days or frozen 1 month.', shelf_life = 'Dough: 24 h refrigerated. Cut: 2 days refrigerated / 1 month frozen — cook from frozen.', plating_suggestions = 'Component recipe — cook to order in well-salted water; the noodle should be the last thing finished and the first thing eaten.' where created_by is null and title = 'Course 3 — Noodle Dough' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Stand mixer with dough hook (hand-mixing this much butter into dough is impractical); loaf tins', chef_notes = 'Add the butter only after the dough has already developed full gluten strength (windowpane test) -- adding it earlier blocks gluten formation and the dough never comes together. Keep the dough cool throughout mixing (butter should stay solid, not melt in) or it turns greasy instead of enriched.', storage = 'Keeps well wrapped at room temperature for 2 days thanks to the butter/egg content; refrigerate to extend, but bring back to room temperature before serving as the fat firms up cold.', shelf_life = '2-3 days at room temperature, well wrapped; freezes very well.', plating_suggestions = 'The torn, feathery crumb is the whole point of a good brioche -- pull rather than slice for the bread basket where possible.' where created_by is null and title = 'Brioche' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Heavy oven tray or cast-iron pan; small pot for brown butter', chef_notes = 'Roast harder than feels polite — deep amber edges are where cauliflower becomes interesting. Make the brown butter to hazelnut stage and add yuzu off the heat; it spits, and the aroma rides the foam.', storage = 'Components hold separately a day; the dish is assembled hot to order.', shelf_life = 'Roasted florets: 24 h refrigerated (re-roast to serve). Brown butter yuzu: 3 days, re-warmed gently.', plating_suggestions = 'Florets stacked with height, butter spooned over at the pass so it pools and beads, toasted seeds last for contrast — serve while the butter still smells nutty.' where created_by is null and title = 'Roasted Cauliflower, Brown Butter, Yuzu & Sunflower Seeds' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Blender; fine sieve; chilled containers', chef_notes = 'A light base that lives on freshness — blend cold, strain fine, and season with restraint so it works as both soup and dressing. Taste chilled; that''s how it''s served.', storage = 'Refrigerated, airtight, 2 days — this base is about brightness, not shelf life.', shelf_life = '48 hours refrigerated.', plating_suggestions = 'As soup: poured tableside over a small arranged garnish. As dressing: tossed at the last second over delicate leaves.' where created_by is null and title = '"SPA" Soup/Dressing Base' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Escargot dish or trays with wells; piping bag (optional) for the herb butter', chef_notes = 'Push the snail in first, then seal with butter on top — butter on the bottom only leaves the shell undressed and burns before the snail heats through.', storage = 'Herb butter can be rolled in cling film and kept refrigerated up to 1 week, or frozen up to 1 month — portion before freezing for faster service.', shelf_life = 'Herb butter: 1 week refrigerated / 1 month frozen. Baked: serve immediately.', plating_suggestions = 'Serve straight from the escargot dish, still bubbling, with crusty bread and a small fork or tongs — the dish itself is the presentation, no extra plating needed.' where created_by is null and title = 'Escargots de Bourgogne' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Stand mixer; sugar thermometer; oiled tray; toasted coconut for rolling', chef_notes = 'Pour the syrup at exactly the stated temperature — a few degrees decides between soup and rubber. Roll cut pieces in toasted coconut immediately; the sticky window is short.', storage = 'Airtight at room temperature up to 2 weeks — never refrigerate, they weep.', shelf_life = '14 days airtight at room temp.', plating_suggestions = 'Cut in imperfect generous cubes; lovely torched briefly on the plate so the coconut edges catch — a s''more note without the campfire.' where created_by is null and title = 'Coconut Marshmallow' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Heavy pot; separate pot for steaming clams; whisk', chef_notes = 'Steam the clams just to opening and hold them out — they go back in at the end or they turn to erasers. The clam liquor is the flavour; strain it of sand and use every drop.', storage = 'Refrigerated 2 days; reheat gently, never boiled, clams added back warm.', shelf_life = '48 hours refrigerated; does not freeze well (cream and potato both object).', plating_suggestions = 'Thick but pourable — a spoon should stand briefly, then fall; oyster crackers and a scatter of chives, bacon lardons if the house leans rich.' where created_by is null and title = 'New England Clam Chowder' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Hands and a bowl of hand vinegar (tezu); yanagiba for the neta', chef_notes = 'Three to four movements, no more — overworked nigiri is dense nigiri. The rice should hold on the way to the mouth and collapse inside it; that contradiction is the entire craft.', storage = 'Technique recipe — shaped and served within minutes.', shelf_life = 'Minutes; nigiri does not wait.', plating_suggestions = 'Two per order, laid parallel at a slight diagonal, brushed with nikiri rather than served with a soy dish where the house does Edomae service.' where created_by is null and title = 'Nigiri — Shaping Technique' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Heavy pot or deep tray; thermometer (oil at 85-95°C); sterile jars if holding', chef_notes = 'Low and slow in oil barely shivering — boiling oil fries them and collapses the texture. Add thyme and garlic to the oil, not the pan after; the infusion is half the dish.', storage = 'Submerged in their oil, refrigerated, up to 2 weeks — the oil becomes a second product for dressings.', shelf_life = '14 days refrigerated, always submerged.', plating_suggestions = 'Component recipe — lift from the oil, flash in a hot pan for colour, and use on toast, beside meat, or through pasta; drizzle the confit oil as the finishing touch.' where created_by is null and title = 'Confit Wild Mushrooms' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Large heavy pot; chinois; ladle for skimming; patience measured in hours', chef_notes = 'Roast the bones dark and skim without mercy — a clean reduction is skimmed dozens of times. Reduce to just before sauce consistency; the Final Sauce recipe takes it the rest of the way.', storage = 'Refrigerated 5 days (it sets solid — a good sign) or frozen in cubes 3 months.', shelf_life = '5 days refrigerated / 3 months frozen.', plating_suggestions = 'Component — the mother of the lamb sauces; even a teaspoon, warmed loose, turns a plate serious.' where created_by is null and title = 'Lamb Reduction' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Large heavy pot; sieve; spice bag or muslin; freezer space for the mother', chef_notes = 'A living stock — strain after every use, boil before every use, and refresh aromatics each third run. Kept honestly, it gets deeper for years; the discipline is the recipe.', storage = 'Refrigerated 5 days between uses (boil to refresh) or frozen indefinitely as the mother stock.', shelf_life = 'Boil every 5 days refrigerated, or freeze; discard only if ever left warm.', plating_suggestions = 'Component — braise poultry, pork, eggs or tofu in it; serve glossy with a spoon of the stock itself and something green for contrast.' where created_by is null and title = 'Chinese Master Stock (Lu Shui)' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Blender; gloves; large bowl; fermentation-safe containers', chef_notes = 'The vegan swap (kelp/shiitake for the fish elements) needs extra umami patience — a longer ferment closes the gap. Keep everything scrupulously clean; wild fermentation rewards hygiene.', storage = 'Paste alone: refrigerated 2 weeks. On vegetables, fermenting: weeks to months, flavour deepening.', shelf_life = 'Paste 14 days refrigerated; finished kimchi months, refrigerated.', plating_suggestions = 'Component — beyond kimchi itself: a spoon through fried rice, in a toasted cheese sandwich, or loosened into a dressing.' where created_by is null and title = 'Vegan Kimchi Paste' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Blender for the rempah; heavy pot; noodle baskets', chef_notes = 'Fry the rempah until the oil splits and stains — the depth of the whole laksa is decided in those ten minutes. Coconut milk in at the end, barely simmered, never boiled hard.', storage = 'Broth: refrigerated 3 days / frozen 1 month. Assemble bowls to order.', shelf_life = 'Broth 3 days refrigerated / 1 month frozen.', plating_suggestions = 'Build the bowl in layers — noodles, protein, broth poured over, then the crown: fried shallots, laksa leaf, sambal, half a boiled egg with the yolk facing up.' where created_by is null and title = 'Laksa (Malaysian Coconut Curry Noodle Soup)' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Whisk and bowl or immersion blender; jar', chef_notes = 'Build a proper mayo first, then season with truffle at the end, off any heat, tasting as you go — truffle oil overdoses in drops, not spoons. A little real truffle paste grounds the perfume.', storage = 'Refrigerated, airtight, 5 days (fresh egg base).', shelf_life = '5 days refrigerated.', plating_suggestions = 'Component — a restrained dollop or piped dots beside fries, croquettes or seared beef; the aroma should arrive as a suggestion, not an announcement.' where created_by is null and title = 'Truffle Mayonnaise' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Bench scraper for dividing and shaping into balls', chef_notes = 'Balling the dough tightly (a taut, smooth surface with the seam pinched underneath) is what gives the rise structure for a good crust -- a loosely shaped ball spreads flat instead of puffing at the edges. Bring to room temperature before stretching if it was refrigerated; cold dough tears instead of stretching.', storage = 'Portioned balls keep refrigerated, lightly oiled and covered, 24-48 hours -- flavour actually improves with a slow cold ferment.', shelf_life = '2 days refrigerated; freeze portioned if holding longer.', plating_suggestions = 'Stretch by hand rather than rolling with a pin -- a pin knocks out the air bubbles that give the baked crust its structure.' where created_by is null and title = 'Basic Pizza Dough' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Food processor for the dried seafood; heavy pot; sterilized jars; patience', chef_notes = 'Every element is fried separately to deep gold before they unite — that''s why real XO costs what it costs. Low and slow at the combine stage; the sugars scorch in a blink.', storage = 'Oil-capped, refrigerated, 1 month — flavour peaks after the first week.', shelf_life = '1 month refrigerated; always spoon with clean utensils.', plating_suggestions = 'Component — a small hot spoonful over scallops, steamed egg, or plain greens; XO is jewellery, priced and portioned accordingly.' where created_by is null and title = 'XO Sauce' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Whisk; silicone mat; offset spatula; stencils', chef_notes = 'The house neutral tuile — rest the mix so the flour hydrates and spreads evenly. Colour or flavour it in small splits rather than committing the whole batch.', storage = 'Mix: refrigerated 1 week. Baked: airtight 3-4 days.', shelf_life = 'Mix 7 days refrigerated; baked 3-4 days airtight.', plating_suggestions = 'Component — the architectural element: curves, corals, and shards; one confident piece per plate beats three timid ones.' where created_by is null and title = 'Tuile Mix' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Pasta machine for the dough; scale; small offset spatula or butter knife for filling', chef_notes = 'Roll the dough thinner than seems safe — a wonton wrapper should read the filling''s colour through it. Keep filling cold and wrappers covered; both punish neglect within minutes. The fold matters less than the seal: no air pockets, or they burst.', storage = 'Wrappers: refrigerated, dusted and wrapped, 2 days. Filled: freeze on trays immediately, up to 2 months.', shelf_life = 'Wrappers: 2 days refrigerated. Filled frozen: 2 months, cook from frozen.', plating_suggestions = 'Component recipe — in broth, serve 5-6 with the pleats up; fried, stand them seam-down with a dipping pot; either way the translucence is the quality signal.' where created_by is null and title = 'Wonton Dough & Filling Technique' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Dehydrator or low oven (for the 8-hour dry); mortar and pestle', chef_notes = 'This is a long, mostly hands-off process — start it a day ahead. The tomatoes should shrivel and concentrate, not turn fully leathery; check at the 6-hour mark if your oven runs hot.', storage = 'Dried tomato mix keeps refrigerated, airtight, up to 4-5 days once combined with the cheese and reduction.', shelf_life = '4-5 days refrigerated.', plating_suggestions = 'Rough and rustic is correct here — don''t over-process into a paste, the point is visible texture from the pounded mix.' where created_by is null and title = 'Cherry Tomato Salsa' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Mandoline or sharp knife for paper slices; pot for the pickle; sterile jar', chef_notes = 'Young ginger, sliced paper-thin with the grain, salted, then hot-pickled — the natural pink blush only comes from truly young ginger; dye is beneath the house.', storage = 'In pickle liquid, refrigerated, 1 month and improving the first week.', shelf_life = '1 month refrigerated, submerged.', plating_suggestions = 'A small loose fold of slices to the side — it''s a palate cleanser between fish, and its placement says the kitchen knows that.' where created_by is null and title = 'Gari (Pickled Sushi Ginger)' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Carbon-steel wok; highest burner available; wok spatula; day-old rice (equipment, honestly)', chef_notes = 'Day-old, cold, separated rice — non-negotiable. Cook in small batches; overloading the wok kills the heat and you end up steaming. The ''breath of the wok'' only appears when the pan stays screaming hot.', storage = 'Serve immediately. Cooked fried rice keeps refrigerated 2 days but is a shadow of itself.', shelf_life = 'Best within minutes; 2 days refrigerated as staff food.', plating_suggestions = 'A loose mound, never pressed into a dome mould in this kitchen''s style — height and separation show the technique; a few bright garnish points, nothing wet on top.' where created_by is null and title = 'Fried Rice — Wok Technique' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Stand mixer; sugar thermometer; terrine or ring moulds; parchment', chef_notes = 'A nougat glacé is three disciplines in one: a proper Italian meringue, honest caramelised nuts, and cream folded with restraint. Slice with a hot dry knife straight from the freezer.', storage = 'Frozen in its mould, well wrapped, up to 2 weeks.', shelf_life = '2 weeks frozen; slices soften pleasantly in the 5 minutes on the plate.', plating_suggestions = 'A clean slice showing the nut-and-fruit mosaic, red-fruit coulis in a line beside — the classic pairing exists because it''s right.' where created_by is null and title = 'Frozen Nougat' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Small pot; spatula; immersion blender; sieve for the purée seeds', chef_notes = 'Strain the purée — seeds in ganache read as a mistake, not rusticity. The acidity tightens the emulsion fast; add the purée warm and blend immediately.', storage = 'Refrigerated, film on surface, 1 week.', shelf_life = '7 days refrigerated.', plating_suggestions = 'Component — its deep rose interior earns a cut face: use in bonbons, tart fillings, or piped between layers where slicing reveals it.' where created_by is null and title = 'Ganache — Raspberry' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Heavy pot with headroom (it foams); whisk; heatproof jar', chef_notes = 'Take the caramel to true amber before the soy goes in — pale caramel plus soy tastes like sweet soup. It will seize, then smooth; keep whisking.', storage = 'Refrigerated, airtight, 3 weeks; loosen gently warm before use.', shelf_life = '21 days refrigerated.', plating_suggestions = 'Component — the sweet-salt bridge: over vanilla ice cream, mochi, or brushed on grilled pork; drawn lines hold their edge nicely.' where created_by is null and title = 'Soya Caramel Sauce' and coalesce(chef_notes,'') = '';
update recipes set equipment = '900g loaf tin, greased or lined', chef_notes = 'Proof just to the rim of the tin before baking, not over it -- an over-proofed loaf collapses the moment it hits the oven and gives a dense band under the crust. Tap the base after baking; a hollow sound means it is fully cooked through.', storage = 'Keep in a bread bag or wrapped at room temperature -- this loaf has no crust texture worth preserving unwrapped, unlike the lean breads above.', shelf_life = '3-4 days at room temperature, well wrapped; slices freeze well for toasting later.', plating_suggestions = 'Let cool fully before slicing for sandwiches -- warm sandwich bread compresses and tears under a knife.' where created_by is null and title = 'Basic White Sandwich Loaf' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Wok or wide pot; ladle; rice cooker or steamer running alongside', chef_notes = 'Crack the coconut cream first — fry the paste in the separated fat until it smells cooked, not raw. Balance at the end, always in this order: salt (fish sauce), sweet (palm sugar), then aroma (lime leaf, basil) off the heat.', storage = 'Curry sauce alone keeps refrigerated 3 days; assemble bowls to order.', shelf_life = 'Sauce: 3 days refrigerated / 1 month frozen. Assembled bowl: immediately.', plating_suggestions = 'Rice and curry in the same wide bowl, protein visible above the sauce line, Thai basil and sliced chilli added at the pass so they arrive fragrant, not wilted.' where created_by is null and title = 'Green Curry Bowl (Assembly)' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Smoker or low oven; probe thermometer; two forks or bear claws; spray bottle', chef_notes = 'It''s done at probe-tender (~95°C internal), not at a clock time — the stall is normal, wrap through it. Rest a full hour before pulling and pull while warm; cold shoulder shreds into strings.', storage = 'Pulled and moistened with juices: refrigerated 4 days, frozen 3 months in flat bags.', shelf_life = '4 days refrigerated / 3 months frozen — reheat covered with a splash of its own juice.', plating_suggestions = 'Serve glistening, tossed at the last moment with just enough sauce to coat; pile height matters — flat pulled pork looks tired.' where created_by is null and title = 'Pulled Pork Shoulder' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Heavy pot or rice cooker with congee mode; ladle', chef_notes = 'The 1:10 rice-to-liquid patience is the recipe; stir more toward the end as it thickens and wants to catch. A neutral congee is correct — the toppings carry the personality.', storage = 'Refrigerated 3 days; it sets solid — loosen with stock when reheating, never water alone.', shelf_life = '3 days refrigerated.', plating_suggestions = 'Serve steaming with toppings arranged in distinct piles on the surface — century egg, scallion, fried shallot, white pepper — so the guest stirs their own bowl.' where created_by is null and title = 'Congee Base' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Wok or pot; ladle; small bowl for the starch slurry', chef_notes = 'The name is the recipe: white pepper heat and black vinegar sourness both added at the end, both louder than feels polite. Egg ribbons form off the boil in a slow spiral, never stirred hard.', storage = 'Refrigerated 2 days; the starch thins on reheating — refresh with a small slurry.', shelf_life = '48 hours refrigerated.', plating_suggestions = 'Serve immediately while the pepper is sharp; a final drop of vinegar and sesame oil in the bowl at the pass wakes a held batch.' where created_by is null and title = 'Hot and Sour Soup' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Small pot for infusing the honey; grill or hot pan for the peach', chef_notes = 'Strain the spiced honey while still warm — it thickens and gets much harder to pass through a sieve once cool.', storage = 'Spiced honey is shelf-stable at room temperature in a sealed jar for several weeks; the grilled peach is best made same-day.', shelf_life = 'Spiced honey: several weeks at room temperature. Assembled plate: serve immediately, burrata weeps once cut.', plating_suggestions = 'Split the burrata open just before serving so the centre stays creamy; scatter, don''t stack, the tomatoes and peach around it.' where created_by is null and title = 'Burrata, Inca Tomatoes, Grilled Peach, Spiced Honey' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Small pot; whisk; basting brush', chef_notes = 'Reduce to a lazy ribbon — thin glaze slides off, thick glaze burns in patches. Always split the batch: marinade portion touches raw pork, glazing portion stays clean.', storage = 'Refrigerated, airtight, 2 weeks.', shelf_life = '14 days refrigerated (clean portion).', plating_suggestions = 'Component — layered on in the final roasting passes; a spoon of warmed glaze over the sliced meat at the pass restores the lacquer.' where created_by is null and title = 'Char Siu Glaze' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Blender or food processor; spatula; airtight container', chef_notes = 'Blend the chipotles adobo and all, then balance smoke with acid — a squeeze of lime keeps it from tasting like an ashtray. Rest an hour before judging the heat; it grows.', storage = 'Refrigerated, airtight, 5 days.', shelf_life = '5 days refrigerated.', plating_suggestions = 'Serve in a shallow bowl swiped with the back of a spoon, a little oil pooled in the swirl — rustic but deliberate.' where created_by is null and title = 'Chipotle Dip' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Mixing bowl; fork or masher', chef_notes = 'This batch scales for volume service (from 4.5kg whole avocado) — the mayonnaise and sushi vinegar help it hold slightly better over service than a classic lime-only guacamole, useful if this needs to sit on a line.', storage = 'Press plastic wrap directly onto the surface, refrigerate.', shelf_life = 'Holds a little longer than classic guacamole thanks to the mayonnaise — still best within 6-8 hours refrigerated, surface-wrapped.', plating_suggestions = 'Consistent texture batch to batch since it''s built to a ratio — good for scooped quenelles that need to look uniform across many plates.' where created_by is null and title = 'Guacamole (House Style)' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Rolling pin (or dough sheeter if available); ruler for consistent triangle sizing; proofing box or warm humid spot (about 24-27C) for the final proof', chef_notes = 'Butter and dough must be the same firmness before each fold -- if the butter is colder than the dough it cracks and tears through instead of laminating in even layers; if warmer, it squeezes out. Chill between every fold (minimum 30 minutes) -- skipping this is the single most common reason lamination collapses into a dense, bready croissant.', storage = 'Best baked fresh -- shaped, unbaked croissants can be held overnight in the fridge or frozen for a longer hold, then proofed and baked to order.', shelf_life = 'Baked croissants are best within a few hours; unbaked shaped dough freezes well for up to a month.', plating_suggestions = 'The honeycomb layer structure should be visible at the cut ends -- trim tips neatly before baking so the layers show cleanly.' where created_by is null and title = 'Classic Croissants' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Wide heavy pot; ovenproof crocks; broiler or salamander', chef_notes = 'The onions take 45+ minutes to true deep amber — that colour IS the soup; deglaze the fond repeatedly as it builds. Dry the bread fully before it goes on or it dissolves.', storage = 'Soup base improves overnight; refrigerated 4 days, frozen 3 months (without bread/cheese).', shelf_life = '4 days refrigerated / 3 months frozen (base only).', plating_suggestions = 'Crock service, cheese broiled to a leopard-spotted overhang down the sides — the pull when the spoon breaks through is the moment.' where created_by is null and title = 'French Onion Soup' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Oven for roasting; blender or food processor', chef_notes = 'Roast the beetroot whole and unpeeled in foil — peeling before roasting loses moisture and colour. Peel while still warm; once cold the skin grips much harder.', storage = 'Keeps refrigerated, airtight, up to 4-5 days — the parmesan shortens its life slightly compared to a dairy-free pesto.', shelf_life = '4-5 days refrigerated.', plating_suggestions = 'The colour is the whole appeal — use it as a bold swipe or dot rather than folding it into something else and losing the magenta.' where created_by is null and title = 'Beetroot Pesto' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Blender; fine sieve; chilled bowls (actually chill them)', chef_notes = 'Ripe tomatoes or don''t bother. Blend with the bread and oil until it emulsifies to silk, then strain. Season cold — chilling mutes salt and sherry vinegar, so adjust after refrigeration.', storage = 'Refrigerated, covered, 2 days; the second day is arguably better.', shelf_life = '48 hours refrigerated at peak.', plating_suggestions = 'Icy bowls, a thread of best olive oil, tiny diced garnish scattered like confetti — or pour tableside over the garnish for service theatre.' where created_by is null and title = 'Gazpacho (Chilled Spanish Tomato Soup)' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Small heavy pot; fine chinois; whisk for mounting', chef_notes = 'This is the finishing pass on the lamb reduction: mount cold butter off the boil, season at nappe, and never let it re-boil after mounting or it splits. Taste on a spoon cooled to eating temperature.', storage = 'Hold warm (not hot) through service; refrigerate base unmounted up to 3 days.', shelf_life = 'Unmounted base: 3 days refrigerated. Mounted: this service only.', plating_suggestions = 'Sauce the plate, not the meat — a confident spoon-pull or pool beneath, so the lamb''s crust stays crisp and the gloss shows.' where created_by is null and title = 'Final Sauce (for Lamb Reduction)' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Skin-pricking tool or needle cluster; salt crust tray; rack; very hot oven or grill finish', chef_notes = 'Prick the skin relentlessly — hundreds of holes, none deep enough to reach fat. The salt crust stage dehydrates; the blast stage puffs. Skipping either gives leather, not glass.', storage = 'Keeps refrigerated 4 days; only the dry-pan, skin-down method truly revives the crackle.', shelf_life = '4 days refrigerated; skin at its peak within hours of roasting.', plating_suggestions = 'Cut in clean cubes with a heavy knife through the crackling — the geometric stack with mustard or hoisin beside is the classic siu-yuk presentation for a reason.' where created_by is null and title = 'Crispy Skin Roast Pork Belly (Siu Yuk)' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Air pump or compressor; hanging hooks; ladle for the boiling-water bath; fan or cool dry space for drying; carving knife', chef_notes = 'Separation of skin from fat (the air pump), scalding, glazing, and 24 h of hang-drying — every skipped step shows in the skin. Carve skin-first at the table if the room allows; that''s the theatre the dish was built for.', storage = 'The process is the storage — once roasted, serve within the hour.', shelf_life = 'Serve immediately; leftover meat: 2 days refrigerated for fried rice or noodles (a feature, not a compromise).', plating_suggestions = 'Skin shards on a separate small plate with sugar for dipping; sliced meat with pancakes, batons of cucumber and spring onion, hoisin in a tidy pot — let the guest build.' where created_by is null and title = 'Peking Duck' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Siphon with N2O chargers; fine sieve; scale', chef_notes = 'Strain twice before charging — one fleck blocks the nozzle mid-service. Alcohol fights foams: keep the whisky within the recipe''s ratio, or structure collapses in seconds on the plate.', storage = 'Charged siphon: refrigerated 24 h; shake well before each use.', shelf_life = '24 h in the siphon, refrigerated.', plating_suggestions = 'Dispense last, at the pass, in one moving pass — foam is a 90-second garnish; pair where the whisky''s burn earns its place (chocolate, caramel, coffee).' where created_by is null and title = 'Whisky Foam' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Heavy pot; fine sieve; glasses or moulds', chef_notes = 'Rinse cooked pearls until the water runs clear — surface starch is what makes bad sago gluey. Sweeten the base slightly more than tastes right warm; chilling mutes sugar.', storage = 'Refrigerated, covered, 3 days; loosen with coconut milk before serving.', shelf_life = '3 days refrigerated; no freezing.', plating_suggestions = 'Glass service so the frog-spawn texture reads as intentional elegance; a contrasting syrup layer (palm sugar, mango) poured at the table adds theatre.' where created_by is null and title = 'Sago Pudding' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Pot; thermometer; shallow tray or moulds; sharp knife for dicing', chef_notes = 'Add yuzu juice as late and as cool as the setting agent allows — boiling it away wastes the most expensive ingredient in the section. Set thin for dicing into precise cubes.', storage = 'Refrigerated, covered, 4 days.', shelf_life = '4 days refrigerated.', plating_suggestions = 'Component — scatter glass-clear cubes for acid pops and light play; they read as jewellery on dark surfaces.' where created_by is null and title = 'Yuzu Jelly' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Deep, narrow pot for frying; thermometer; wide pan for the syrup', chef_notes = 'Fry low — 150°C, not a degree more — turning constantly; the dumplings must colour slowly all the way through or they stay raw inside. Syrup should be warm, not hot, when they go in, and they need a full hour to drink it up.', storage = 'Keeps in its syrup, covered, at room temperature 2 days or refrigerated up to 1 week.', shelf_life = '2 days room temp / 7 days refrigerated, always submerged in syrup.', plating_suggestions = 'Two per portion in a shallow bowl with a spoon of syrup, cardamom dust and a few pistachio slivers — resist the urge to add more garnish.' where created_by is null and title = 'Gulab Jamun' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Small pot for brown butter; sieve; financier moulds; piping bag for clean fills', chef_notes = 'Manjari''s acidity is the signature — don''t overbake or you flatten the fruit notes into generic chocolate. Overnight batter rest, as with all financiers, pays in crumb.', storage = 'Mix: refrigerated 3 days. Baked: airtight 2 days / frozen 1 month.', shelf_life = 'Batter 3 days; baked 2 days airtight.', plating_suggestions = 'Component — the sponge base for plated chocolate work; trim warm with a ring cutter for clean discs and save the offcuts for crumble.' where created_by is null and title = 'Manjari Financier Mix' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Meat mallet; butcher''s twine; wide braising pan; thermometer', chef_notes = 'Pound even — thickness discipline is what makes the spiral tidy. Sear the tied roll hard before braising; that crust is flavour the sauce will claim. Rest before slicing or the filling shifts.', storage = 'Cooked roll in its sauce keeps refrigerated 3 days; slices reheat gently in the sauce.', shelf_life = '3 days refrigerated / 2 months frozen in sauce.', plating_suggestions = 'Thick spiral slices over the reduced braising sauce, cut surface up; a little gremolata or fried herbs to sharpen the richness.' where created_by is null and title = 'Rolled Stuffed Pork Loin (Braciole-Style)' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Butcher''s twine; roasting tray with rack; sharp scoring knife; thermometer', chef_notes = 'Dry the skin uncovered in the fridge overnight before rolling — that, more than oven tricks, is what makes crackling. Tie tight and evenly; loose rolls cook unevenly and slice ragged.', storage = 'Cooked roll keeps refrigerated, wrapped, up to 4 days; slice cold for clean portions, then reheat.', shelf_life = '4 days refrigerated cooked; crackling is only crisp on day one — re-crisp slices skin-side down in a dry pan.', plating_suggestions = 'Thick slices showing the spiral, skin up; a smear of hoisin or the pan jus underneath, something pickled alongside to cut the fat.' where created_by is null and title = 'Asian Five-Spice Rolled Pork Belly' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Heavy wide pan for reducing the milk; kulfi moulds or ramekins', chef_notes = 'The flavour IS the slow reduction — stir constantly and scrape the fond of toasted milk solids back in; that caramelised note is what separates kulfi from frozen custard. No machine needed, it sets still.', storage = 'Holds in moulds at -18°C up to 2 weeks.', shelf_life = '2 weeks frozen for best flavour; press film to the surface to prevent ice crystals.', plating_suggestions = 'Unmould by dipping briefly in warm water, slice into discs on the bias, scatter with pistachio and a thread of saffron syrup.' where created_by is null and title = 'Kulfi (Indian Ice Cream)' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Sharkskin grater (oroshigane) or finest microplane; small damp cloth', chef_notes = 'Grate in slow circles and let it rest 2-3 minutes — the heat and sweetness develop after grating, then fade within 15. Grate per service, tiny amounts; this is the most perishable luxury in the kitchen.', storage = 'The rhizome: wrapped in damp cloth, refrigerated, 2 weeks. Grated: 15 minutes.', shelf_life = 'Grated paste: minutes. Rhizome: 14 days refrigerated, trimmed as used.', plating_suggestions = 'A small pyramid beside the fish, never dissolved into soy in front of the chef — real wasabi is served where its sweetness can be tasted alone.' where created_by is null and title = 'Fresh Wasabi Paste' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Loaf tins; bench scraper for cutting the rolled log into strands for braiding', chef_notes = 'Chill the rolled, filled log briefly before cutting and braiding -- a warm log squeezes the chocolate filling out through the cut instead of leaving neat swirled layers. Braid loosely rather than tight, since the dough still needs room to expand during proofing.', storage = 'Keeps wrapped at room temperature for 2 days; the chocolate filling means it dries out faster than plain brioche if left uncovered.', shelf_life = '2 days at room temperature, well wrapped; freezes well sliced.', plating_suggestions = 'The swirled cross-section is the entire visual appeal -- always slice to show the cut face, never serve the whole loaf uncut for plating purposes.' where created_by is null and title = 'Chocolate Babka' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Small pot (warm only to dissolve, never boil); scale; bottle', chef_notes = 'The master ratio is the house signature — warm just enough to dissolve sugar and salt, never boiling off the vinegar''s top notes. Batch it; consistency across days matters more than any single day''s brilliance.', storage = 'Sealed bottle, cool cupboard, 3 months — it''s vinegar.', shelf_life = '3 months at room temperature.', plating_suggestions = 'Component — folded into just-cooked rice at the hangiri; the sheen it leaves on each grain is its only, and sufficient, presentation.' where created_by is null and title = 'Sushi Vinegar — Master Ratio (Awase-zu)' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Mortar and pestle or blender; wide pan; jar', chef_notes = 'Pound or pulse coarse — tom yum paste wants texture, not purée. Fry until fragrant and deepened; the nam prik pao note (roasted chilli jam) is what separates house paste from a jar.', storage = 'Oil-capped, refrigerated, 2 weeks; frozen in portions 3 months.', shelf_life = '14 days refrigerated / 3 months frozen.', plating_suggestions = 'Component — dissolve into hot stock at the last minute to keep the aromatics loud; a half-spoon extra in the bowl for guests who ask for spicy.' where created_by is null and title = 'Tom Yum Paste' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Pot; blender; finest sieve; chilled bowls', chef_notes = 'Whites of the leek only — green makes it grey. Sweat, never colour, the vegetables. Strain twice and season cold and assertively; chilled soups eat half your seasoning.', storage = 'Refrigerated, covered, 3 days.', shelf_life = '3 days refrigerated.', plating_suggestions = 'Ice-cold, dead-smooth, chives cut fine as grass — served in a small chilled bowl or glass; simplicity is the luxury here.' where created_by is null and title = 'Vichyssoise (Chilled Leek & Potato Soup)' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Makisu (bamboo mat); sharp wet knife; nori kept dry until the second it''s used', chef_notes = 'One strip of filling, rice spread thin to the edges but for the seal margin — hosomaki punishes greed. Cut in six with a single drawn stroke each, wiping the blade wet between cuts.', storage = 'Technique recipe — rolls are made and served within the hour; nori waits for no one.', shelf_life = 'Within 1 hour; the nori''s crispness is part of the standard.', plating_suggestions = 'Six pieces standing, cut faces up and level — uniform white walls and a centred filling are the visible exam result.' where created_by is null and title = 'Hosomaki — Thin Roll Technique' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Blender for the pesto', chef_notes = 'Fold the parmesan into the pesto by hand rather than blending it in — the method already gets this right; worth flagging to junior cooks since it''s the detail most likely to get skipped under pressure and turn the pesto bitter.', storage = 'Pesto keeps refrigerated, surface covered with a film of olive oil to prevent oxidation, up to 5 days.', shelf_life = 'Pesto: 5 days refrigerated (press plastic wrap directly onto the surface). Dressed tomatoes: best within 1-2 hours of cutting.', plating_suggestions = 'Tear, don''t slice, the stracciatella for texture; dot the pesto rather than pooling it, so each bite gets a hit rather than the plate reading one-note.' where created_by is null and title = 'Mixed Tomato Salad with Basil Pesto & Burrata' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Piping bags (star tip for the choux ring); oven; serrated knife; stand mixer for the praliné cream', chef_notes = 'Pipe the choux ring over a drawn template and bake fully dry — a pale Paris-Brest collapses under its cream. Praliné mousseline must be truly emulsified: beat the butter in only when the base is at room temperature.', storage = 'Baked rings: airtight 1 day or frozen 1 month. Assembled: refrigerated, best within 12 h.', shelf_life = 'Assembled: 12-24 h refrigerated. Components separately: per element.', plating_suggestions = 'Cut face forward — the piped cream rosettes between the split ring are the display; hazelnuts and a modest dusting, nothing else.' where created_by is null and title = 'Paris Brest / Vence / Meringue' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Small pot; spatula; immersion blender; real vanilla pods', chef_notes = 'Infuse the cream with split pods off the heat for 20 minutes — steeping at a boil turns vanilla woody. White-chocolate-based vanilla ganache scorches easily; pour the cream in stages.', storage = 'Refrigerated, film on surface, 1 week; whips into a lighter frosting once matured overnight.', shelf_life = '7 days refrigerated.', plating_suggestions = 'Component — the workhorse: pipe, whip, or glaze; visible vanilla seed speckle is the quality signature, never strain them out.' where created_by is null and title = 'Ganache — Vanilla' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Heavy pot; strainer; dipping vessel deep enough for skewers', chef_notes = 'Like master stock, tare is a living sauce — the drippings from each dipped skewer go back in, and it deepens for years. Boil to refresh between services; never let raw chicken touch the pot itself.', storage = 'Refrigerated between services, boiled before each use; treated properly, indefinite.', shelf_life = 'Boil-refresh cycle; discard only on any warm-holding lapse.', plating_suggestions = 'Component — dip skewers in the final grilling passes so the tare chars in layers; serve with the lacquer still bubbling at the edges.' where created_by is null and title = 'Yakitori Tare' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'One 30x20cm tray, generously oiled; fingers for dimpling', chef_notes = 'Dimple firmly all the way to the tray base, not just the surface -- shallow dimples spring back during baking and disappear, losing the signature pools of oil. A wetter dough than feels comfortable is correct here; resist adding extra flour, which makes the crumb dense instead of open.', storage = 'Best the day it is baked; wrap at room temperature if holding overnight.', shelf_life = '1-2 days at room temperature; toast or re-warm rather than serving day-old focaccia cold.', plating_suggestions = 'Cut into rustic squares or strips rather than neat portions -- the irregular open crumb and oil pools are the point.' where created_by is null and title = 'Simple Focaccia' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Heavy pot for the mornay; gratin dish; microplane for fresh truffle if the budget smiles', chef_notes = 'Undercook the pasta by two full minutes — it finishes in the sauce and oven. Truffle oil, if used, goes in off the heat and with restraint; heat kills the aroma and excess reads cheap. Fresh truffle is shaved at the table, never baked.', storage = 'Assembled unbaked keeps refrigerated 2 days; bake from cold, covered then uncovered.', shelf_life = 'Unbaked: 2 days refrigerated. Baked: serve bubbling; reheats acceptably once.', plating_suggestions = 'Individual gratin dishes with a proper browned crust — the crack of the crust is the first bite; shave truffle over at the pass so the aroma arrives with the plate.' where created_by is null and title = 'Truffle Mac and Cheese' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Heavy pot; rolling pin or mallet for the shells; blender; fine chinois', chef_notes = 'Roast the shells hard and flame the cognac — the toasted-shell and caramel notes are the bisque. Strain twice through the finest mesh you own; grit ruins luxury.', storage = 'Refrigerated 3 days / frozen 2 months (add cream after thawing, not before freezing).', shelf_life = '3 days refrigerated / 2 months frozen (base).', plating_suggestions = 'Shallow warm bowl, a small mound of lobster meat centred, bisque poured around it tableside, a drop of cream and chervil — classic because it works.' where created_by is null and title = 'Lobster Bisque' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Small pot; scale; jar', chef_notes = 'Sweet vinegar for pickling and marinating — dissolve warm, use cold. It should taste distinctly sweet with a clean sharp finish; muddiness means old vinegar or scorched sugar.', storage = 'Sealed, refrigerated, 2 months.', shelf_life = '2 months refrigerated.', plating_suggestions = 'Component — quick-pickles (cucumber, daikon, myoga) cut fine and marinated to translucence; served as bright, palate-resetting accents.' where created_by is null and title = 'Amazu Marinade (Amazu-zu)' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Blender for the dressing; mandoline (optional, for fine apple/celery cuts)', chef_notes = 'Cut the apple as close to service as possible — even with acid in the dressing, exposed apple browns within 10-15 minutes.', storage = 'Roquefort dressing keeps refrigerated, airtight, up to 4-5 days — it''s dairy-based, don''t push it further.', shelf_life = 'Dressing: 4-5 days refrigerated. Assembled salad: serve within 15 minutes of cutting the apple.', plating_suggestions = 'Keep the radicchio leaves whole or torn large as a base, pile the celery-apple mix loosely on top so the caramelized walnuts stay visible, not buried.' where created_by is null and title = 'Celery, Apple & Roasted Walnut Salad with Roquefort Dressing' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Baking tray or tin sized so rolls proof touching each other (this is what gives the soft, tearable sides)', chef_notes = 'Shape each roll by cupping and dragging it in a tight circular motion against an unfloured section of the bench -- a floured bench stops the dough from gripping and the ball never tightens properly. Space rolls to just touch when panned; the shared proofing/baking creates the classic soft pull-apart sides.', storage = 'Keep covered at room temperature -- these dry out fast once cut open to the air.', shelf_life = '1-2 days at room temperature, covered; freeze well.', plating_suggestions = 'Serve pull-apart in the baking tin or tray shape they proofed in -- separating them before service loses the soft-sided texture that makes them worth doing this way.' where created_by is null and title = 'Classic Dinner Rolls' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Panettone paper moulds; long skewers or knitting needles to hang the loaf upside down immediately after baking', chef_notes = 'This lives or dies on the starter/lievito madre strength -- a weak starter simply cannot lift this much butter, egg and sugar and the dough will collapse rather than rise. Hang upside down the moment it comes out of the oven until fully cool (several hours) -- this is not optional, it is what stops the tall structure from collapsing under its own weight while still hot.', storage = 'Wrap well once fully cooled; keeps at room temperature far longer than any other item in this list thanks to the high sugar/fat content acting as a natural preservative.', shelf_life = 'Up to 2-3 weeks well wrapped at room temperature -- genuinely the longest-keeping item here.', plating_suggestions = 'Slice with a serrated knife using a gentle sawing motion, or tear by hand -- the open, stretchy crumb compresses under a straight-down cut.' where created_by is null and title = 'Panettone' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Scale; bottle; funnel', chef_notes = 'The house blending of vinegars for consistency across suppliers — measure by weight and taste against the reference bottle. Consistency is the entire job of this recipe.', storage = 'Sealed, cool cupboard, 3 months.', shelf_life = '3 months room temperature.', plating_suggestions = 'Component — the base for the sushi vinegar and quick pickles; its quality shows up downstream in every bite of shari.' where created_by is null and title = 'Rice Vinegar Blend' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Butcher''s twine; very sharp knife for scoring; rack over tray; thermometer', chef_notes = 'Salt the skin and leave the roll unwrapped in the fridge 24 h — dry skin is non-negotiable for the shatter. Herb paste goes on the meat side only; any on the skin burns and stains.', storage = 'Whole cooked roll keeps refrigerated 4 days; it slices best fully chilled, then flash the slices in a hot oven.', shelf_life = '4 days refrigerated. Crackling: day one only, revivable skin-down in a dry pan.', plating_suggestions = 'Thick slices, crackling ring intact, over white beans or with salsa verde; serve the end pieces to whoever you like best.' where created_by is null and title = 'Classic Italian Porchetta (Rolled Pork Belly)' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Steamer with cloth liner; small pot for the coconut sauce', chef_notes = 'Soak the glutinous rice properly (4+ hours) and steam, never boil — boiled rice turns to porridge. Season the coconut milk boldly with salt; that sweet-salt tension is the whole dish.', storage = 'Dressed rice holds warm up to 4 hours; it hardens when refrigerated and never fully recovers.', shelf_life = 'Serve within 4 hours of dressing. Coconut sauce alone: 3 days refrigerated.', plating_suggestions = 'A neat mound of rice, fanned ripe mango alongside, the salted coconut cream spooned over the rice only, finished with toasted mung beans or sesame for crunch.' where created_by is null and title = 'Mango Sticky Rice' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Blender (the pear matters); bowl or bags for marinating', chef_notes = 'The grated Asian pear is the tenderizer and the sweetness — don''t substitute sugar alone. Marinate thin cuts 2-6 hours; overnight turns the surface mushy.', storage = 'Marinade alone: refrigerated 1 week. With raw meat: cook within 24 h.', shelf_life = '7 days refrigerated (clean); 24 h once on meat.', plating_suggestions = 'Component — cook hard and fast so the sugars char at the edges; serve with lettuce cups and ssamjang and let the table build.' where created_by is null and title = 'Korean Bulgogi Marinade' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Steamer; deep fryer or heavy pot with thermometer; rack for draining', chef_notes = 'Steam first, fry second — the double cook is what gives the impossible pillow-crisp contrast. Fry at 175°C just to golden; the inside is already cooked, you''re only building the shell.', storage = 'Steamed, unfried bao freeze up to 2 months; fry from thawed. Fried: minutes, like any doughnut.', shelf_life = 'Fried: serve within 15 minutes. Steamed stage: 2 months frozen.', plating_suggestions = 'Roll in sugar while hot so it sticks; serve split with the filling piped generously enough to be seen — this is a playful dish, let it look like one.' where created_by is null and title = 'Baonut (Bao Doughnut)' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Silicone mat; offset spatula; template stencil; something curved to drape over while hot', chef_notes = 'Spread thin and even — a tuile forgives nothing. Shape within seconds of leaving the oven; if it stiffens, 20 seconds back in the oven resets it. Work one tray at a time.', storage = 'Airtight with desiccant if you have it, room temperature, 3-4 days — humidity is the enemy.', shelf_life = '3-4 days airtight; minutes once plated on anything moist.', plating_suggestions = 'Component — plant upright or lean at an angle for height; the snap when the spoon breaks it is part of the dessert.' where created_by is null and title = 'Chocolate Tuile' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Hot pan or grill; fine strainer for the dressing (optional, for a cleaner finish)', chef_notes = 'Wagyu''s high fat content means it goes from perfect to overcooked fast — pull it slightly under your target, since carryover during the rest is more pronounced than with leaner cuts.', storage = 'Lime dressing keeps refrigerated, airtight, up to 1 week — shake before use as it will separate.', shelf_life = 'Dressing: 7 days refrigerated. Sliced wagyu: serve immediately, avocado oxidizes within the hour.', plating_suggestions = 'Fan the sliced wagyu over the dressed greens rather than piling it, so each slice shows its sear; spoon the chimichurri in dots, not a single pool, for visual movement across the plate.' where created_by is null and title = 'Wagyu Steak Salad, Avocado, Crispy Onion, Chimichurri' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Pot; thermometer; fine sieve or muslin', chef_notes = 'Kombu out just before the boil (60-65°C is the aroma sweet spot), katsuobushi in off the heat, steeped minutes, not hours — dashi is a tea, not a stock. Second dashi from the spent solids is legitimate for braises.', storage = 'Refrigerated 2 days; freezing dulls it noticeably. Make small, make often.', shelf_life = '48 hours refrigerated at peak.', plating_suggestions = 'Component — the invisible backbone of miso soup, ramen, chawanmushi; clarity in the bowl is your report card.' where created_by is null and title = 'Dashi (Kombu-Katsuo Stock)' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Ice-cold water (equipment, truly); chopsticks for mixing; deep pot; thermometer; rack', chef_notes = 'Mix lazily with chopsticks seconds before frying — lumps and visible dry flour are correct; gluten is the enemy. Batter dies in 15 minutes; make small batches continuously.', storage = 'No storage — the batter is made per round of frying.', shelf_life = 'Batter: 15 minutes. Fried: eaten in the next five.', plating_suggestions = 'Serve on folded paper the moment it stops hissing, tentsuyu and grated daikon beside; lacy, pale-gold edges are the technique showing off.' where created_by is null and title = 'Tempura Batter & Frying Technique' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Tart rings or pie dish; small pot for caramel; ice cream machine for the fior di latte', chef_notes = 'Toast the pecans before they go in — raw nuts in a baked filling stay dull. Pull the caramel darker than comfortable; the bitterness balances a dessert that flirts with too-sweet.', storage = 'Baked pie: room temperature 1 day, refrigerated 3. Caramel: refrigerated 2 weeks.', shelf_life = 'Pie 3 days refrigerated; assembled plate immediately (ice cream).', plating_suggestions = 'A warm slim wedge, quenelle of fior di latte melting against it, caramel drawn in one decisive stroke — serve while the contrast of warm and frozen is alive.' where created_by is null and title = 'Pecan Pie, Fior di Latte & Caramel' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Blender or food processor, ideally high-powered for a silky finish', chef_notes = 'Blend the tahini/garlic/liquid base first before adding the chickpeas — it emulsifies more smoothly than dumping everything in at once. The final extra blend (to incorporate air) genuinely changes the texture — don''t skip it.', storage = 'Keeps refrigerated, airtight, up to 5 days. The beetroot variation keeps the same.', shelf_life = '5 days refrigerated.', plating_suggestions = 'Swirl a well into the centre for oil or garnish rather than a flat surface — classic presentation, and it stops toppings sliding off.' where created_by is null and title = 'Hummus' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Water bath / immersion circulator; instant-read thermometer (critical); hot clean knife for slicing', chef_notes = 'The 45°C internal target is the whole recipe — a few degrees over and the fat renders out and the torchon falls apart on slicing. Wipe and reheat the knife between every slice for clean cuts.', storage = 'Torchon keeps refrigerated, well-wrapped, up to 5 days once cooked and chilled. Gelée keeps refrigerated up to 3 days.', shelf_life = 'Torchon: 5 days refrigerated (raw foie gras itself: use by the supplier''s date before cooking). Gelée: 3 days refrigerated.', plating_suggestions = 'Slice thick enough to hold its shape (about 1.5cm) but not so thick it feels heavy; scatter the gelée cubes rather than centring them, and lean the toasted brioche against the torchon rather than underneath it so it doesn''t go soggy.' where created_by is null and title = 'Foie Gras Torchon with Sauternes Gelée' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Ice cream machine; blender or spice grinder for the sesame; fine sieve', chef_notes = 'Toast the black sesame just to fragrance before grinding — over-toasting turns the base bitter and grey rather than deep charcoal. Grind with a little of the sugar to stop the seeds clumping into paste too early.', storage = 'Base keeps refrigerated, airtight, up to 3 days before churning. Churned ice cream holds at -18°C.', shelf_life = 'Unchurned base: 3 days refrigerated. Churned: 2 weeks at -18°C for best texture, longer is safe but icy.', plating_suggestions = 'Component recipe — quenelle onto a crumble or tuile so the near-black colour reads on purpose against a light element, never on a dark plate.' where created_by is null and title = 'Black Sesame Ice Cream Base' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Low oven or smoker; foil for wrapping; basting brush; thermometer', chef_notes = 'Veal ribs are leaner than pork — they dry where pork forgives. Wrap earlier, baste more, and pull at tender, not falling apart. A gentler glaze (honey over molasses) suits the delicate meat.', storage = 'Cooked: refrigerated 3 days; reheat covered and low with a splash of stock.', shelf_life = '3 days refrigerated / 2 months frozen.', plating_suggestions = 'Serve as a short rack or cut in twos, glaze brushed to a shine; something green and sharp alongside — gremolata or a fennel salad — keeps it elegant rather than roadhouse.' where created_by is null and title = 'Veal Spare Ribs (Kalbsspare Ribs)' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Low oven or smoker; foil or butcher paper for the wrap stage; basting brush', chef_notes = 'Cook to tenderness, not time — the bend test (rack cracks at the surface when lifted from one end) beats any timer. Glaze only in the last 20 minutes; sugar before that burns bitter.', storage = 'Cooked ribs keep refrigerated up to 4 days — reheat gently, covered, with a splash of water before final glazing.', shelf_life = '4 days refrigerated / 2 months frozen (before glazing for best results).', plating_suggestions = 'Cut between bones with confidence, stack loosely, brush a final coat of warm sauce for shine and scatter something sharp — pickled onion or slaw — beside.' where created_by is null and title = 'BBQ Pork Spare Ribs' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'High-speed blender; sieve; whisk', chef_notes = 'Silken tofu only, blended past the point you think is enough — any grain betrays the trick. Season with enough acid and a fat element (white chocolate or coconut) so it eats as dessert, not health food.', storage = 'Refrigerated, covered, 2 days.', shelf_life = '48 hours refrigerated.', plating_suggestions = 'Serve like a panna cotta''s lighter cousin — quenelle or glass, with something roasted (sesame, kinako) for depth; most guests won''t clock the tofu until told, which is the fun.' where created_by is null and title = 'Tofu Mousse' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Non-stick or carbon pan with lid; gyoza wrappers; small water bowl for sealing', chef_notes = 'The crisp-steam-crisp rhythm: sear flat-side down, add water, lid on, then finish uncovered until the bottoms re-crisp. Pleat toward one direction only — it''s faster and looks intentional.', storage = 'Filled raw: freeze on trays then bag, up to 2 months. Never refrigerate raw filled gyoza more than a few hours — wrappers sog.', shelf_life = 'Frozen raw: 2 months, cook from frozen. Cooked: immediately.', plating_suggestions = 'Line them up seared-side up, slightly overlapping, dipping sauce in reach; a lace ''skirt'' (flour-water slurry in the steam water) turns six gyoza into a showpiece.' where created_by is null and title = 'Gyoza' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Small pot; spatula; immersion blender for the shine; thermometer', chef_notes = 'Reduce the fruit purée slightly before it meets the chocolate — water is ganache''s enemy. Emulsify with the blender held under the surface; the gloss you get is the gloss you keep.', storage = 'Refrigerated, film on surface, 1 week; bring to piping temperature slowly.', shelf_life = '7 days refrigerated.', plating_suggestions = 'Component — pipe as dots or teardrops where the passion-fruit sharpness can cut something rich; pairs naturally with coconut and dark chocolate elements.' where created_by is null and title = 'Ganache — Mango-Passion' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Thermometer; immersion blender; sieve; shallow container or moulds', chef_notes = 'A crémeux is a custard-ganache hybrid — cook the anglaise to 82-84°C, pour over the Illanka in stages, and blend to full gloss. The couverture''s red-fruit acidity is the point; don''t bury it under vanilla.', storage = 'Refrigerated, film on surface, 3 days; pipeable straight from the fridge after a brief beat.', shelf_life = '3 days refrigerated.', plating_suggestions = 'Component — pipe in bold domes; its dark sheen and sharp finish pair with red fruit and toasted nuts. Slice-throughs stay clean and glossy.' where created_by is null and title = 'Illanka Crémeux' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Dehydrator or low oven; blender for the rice paste; fryer for the puff', chef_notes = 'Cooked rice blended, spread thin, dried fully bone-dry, then flash-fried — any residual moisture and it bends instead of puffing. Season the second it leaves the oil.', storage = 'Dried sheets: airtight, weeks. Fried: airtight with desiccant, 2 days.', shelf_life = 'Dried unfried sheets: 1 month airtight. Puffed: 48 hours.', plating_suggestions = 'Component — a dramatic shard for height and crunch on tartares and crudo; its bubbled surface catches sauces beautifully.' where created_by is null and title = 'Rice Cracker' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Tall stockpot tradition behind it; noodle baskets; ladle; char tool for onion/ginger', chef_notes = 'Assembly discipline: noodles hot, raw beef sliced paper-thin laid on top, and broth poured boiling AT the table or pass so it cooks the beef in the bowl. The broth must arrive at a rolling temperature or the ritual fails.', storage = 'Broth: refrigerated 4 days / frozen 3 months. Bowls: assembled to order only.', shelf_life = 'Broth 4 days refrigerated; assembled bowl immediate.', plating_suggestions = 'Herb plate on the side — Thai basil, sprouts, lime, chilli — never in the bowl; the guest finishes the dish, that''s pho.' where created_by is null and title = 'Pho Bo Bowl (Assembly)' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Heavy-bottomed pot; whisk; immersion blender if a smooth finish is wanted', chef_notes = 'Simmer gently and taste at temperature you''ll serve — cold dulls sweetness and sharpens vinegar, so a sauce balanced hot reads different on a cold brisket sandwich. Let it rest a day; it rounds noticeably.', storage = 'Refrigerated, airtight, up to 3 weeks — it''s essentially a preserve.', shelf_life = '21 days refrigerated.', plating_suggestions = 'Component recipe — brush warm onto glazing meats, serve extra in a small pot; never pool it under sliced brisket, it drowns the smoke.' where created_by is null and title = 'House BBQ Sauce' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Two pots (they never meet); fine strainer for the ponzu; bottles', chef_notes = 'Two house workhorses: ponzu steeped cold with citrus and katsuobushi (never boiled — the aroma is the point), teriyaki reduced to a light gloss. Label clearly; they look alike and forgive nothing when swapped.', storage = 'Both refrigerated, sealed: ponzu 3 weeks, teriyaki 1 month.', shelf_life = 'Ponzu 21 days / teriyaki 1 month, refrigerated.', plating_suggestions = 'Component — ponzu pooled beneath crudo or tataki at the last minute; teriyaki brushed in layers over grilled items until lacquered.' where created_by is null and title = 'Ponzu & Teriyaki' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Whisk or jar for shaking', chef_notes = 'Two draft ratios are recorded here — confirm with the kitchen which is the current standard before scaling up, so the batch matches what''s actually being served.', storage = 'Keeps refrigerated, airtight, up to 1-2 weeks — vinaigrette-style, no dairy or egg.', shelf_life = '1-2 weeks refrigerated; shake or re-whisk before use as it will separate.', plating_suggestions = 'Dress just before serving, not in advance — even an oil-based dressing will wilt delicate leaves if it sits.' where created_by is null and title = 'Salad Dressing Mix' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Oven tray; blender; fine sieve for silk', chef_notes = 'Roast the squash to caramelised edges before it ever meets liquid — boiled squash soup tastes of water and regret. Balance with acid at the end; squash''s sweetness needs a counterweight.', storage = 'Refrigerated 4 days / frozen 3 months.', shelf_life = '4 days refrigerated / 3 months frozen.', plating_suggestions = 'Velvet pour tableside over a garnish island — toasted seeds, brown butter, a little chilli oil; the surface contrast against the orange is the plate.' where created_by is null and title = 'Roasted Butternut Squash Soup' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Stand mixer; scale; piping bags with round tip; templates; oven you have personally calibrated', chef_notes = 'Weigh everything, including the egg whites, and learn your macaronage stopping point — figure-eight ribbon that settles in 20 seconds. Rest until a skin forms before baking; feet come from patience, not luck.', storage = 'Filled macarons need 24 h refrigerated maturation — they''re genuinely better on day two. Keep refrigerated up to 5 days, serve at room temp.', shelf_life = '5 days refrigerated filled; shells alone freeze 1 month.', plating_suggestions = 'Serve in odd numbers, feet visible in profile; on a plated dessert, one macaron used as a lid or crown beats five scattered.' where created_by is null and title = 'Macarons' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Financier or small moulds; small pot for brown butter; sieve', chef_notes = 'Brown the butter to full hazelnut and let it cool before it meets the eggs. Rest the batter overnight — financiers bake with a better hump and finer crumb on day two.', storage = 'Batter: refrigerated 3 days. Baked: airtight 2 days, or frozen 1 month.', shelf_life = 'Batter 3 days refrigerated; baked 2 days airtight / 1 month frozen.', plating_suggestions = 'Component or petit four — serve slightly warm when possible; the crisp shell against molten-adjacent crumb is the point.' where created_by is null and title = 'Chocolate Financier' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Whisk or small blender; fine microplane if using fresh zest', chef_notes = 'Emulsify only lightly — yuzu dressing should stay loose and bright, not thick like a mayo-based dressing. Add the yuzu off any heat; its aroma is volatile and disappears fast.', storage = 'Keeps refrigerated, airtight, up to 1 week — shake before each use.', shelf_life = '7 days refrigerated; aroma is best in the first 3.', plating_suggestions = 'Dress delicate leaves, raw fish or blanched greens at the last second; it also works spooned as a finishing sauce over crudo where its perfume can hit the nose first.' where created_by is null and title = 'Yuzu Dressing' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Pot; whisk; refractometer if the pastry section owns one; storage bottles', chef_notes = 'This is the house''s sorbet backbone — a stable sugar/glucose ratio so any fruit purée added churns to the same texture. Measure, don''t improvise; sorbet forgives nothing in sugar balance.', storage = 'Refrigerated in sealed bottles up to 1 month — it''s essentially syrup.', shelf_life = '1 month refrigerated.', plating_suggestions = 'Component — blend with fruit purée per the ratio card and churn; correct base shows as sorbet that scoops clean at -14°C without icing.' where created_by is null and title = 'Sorbet Syrup (base)' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Tart moulds; rolling pin; fine sieve for the custard', chef_notes = 'Strain the custard twice and fill the shells only after the oven is fully at temperature — the filling must set before the pastry over-browns. Pull them the moment the centre still trembles like a soft wobble.', storage = 'Best within hours of baking. Refrigerate up to 2 days; refresh 5 minutes at 160°C to re-crisp the pastry.', shelf_life = 'Same day ideal; 2 days refrigerated maximum. Do not freeze baked tarts.', plating_suggestions = 'Serve barely warm, naked on the plate — the glassy yellow surface is the presentation; any garnish on top reads as a mistake.' where created_by is null and title = 'Hong Kong-Style Egg Tarts' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Mixing bowl', chef_notes = 'Dice the avocado last, right before combining — it''s the first thing to brown and the most visually obvious if it does.', storage = 'Best made to order; if holding, press plastic wrap onto the surface and refrigerate briefly.', shelf_life = 'Same-day, ideally within 1-2 hours of dicing the avocado.', plating_suggestions = 'Keep the dice visible and distinct rather than crushing it together — the different colours (avocado, tomato, chilli, coriander) should read as separate pieces.' where created_by is null and title = 'Avocado Salsa' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Blender for the dressing', chef_notes = 'This dressing recipe is a large batch (3L+) — scale down for à la carte service, or keep it in rotation as a house dressing used across multiple dishes.', storage = 'Caesar dressing (egg-based) keeps refrigerated, airtight, up to 3-4 days — shorter than an oil-only dressing because of the raw yolk.', shelf_life = 'Dressing: 3-4 days refrigerated, raw-egg-based. Assembled salad: serve immediately, leaves wilt fast under the dressing''s acidity.', plating_suggestions = 'Stack whole baby lettuce leaves loosely rather than chopping them, so the Caesar dressing coats rather than drowns them; shave parmesan tableside if possible for aroma.' where created_by is null and title = 'Mini Lettuce, Caesar Dressing, Parmesan, Bacon Croutons' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Stand mixer or whisk; ring moulds or glasses; piping bags', chef_notes = 'Fold the cream in thirds and stop early — the last streaks disappear during piping, and an overfolded mousse sets dense. The kirsch is the signature: enough to notice, not enough to burn.', storage = 'Set mousse holds refrigerated 2 days; freezes in moulds up to 2 weeks for glazing workflows.', shelf_life = '2 days refrigerated / 2 weeks frozen in moulds.', plating_suggestions = 'Layer the classic trio visibly — dark sponge, cherry, mousse — and finish with a real amarena or griotte on top, not a maraschino impostor.' where created_by is null and title = 'Black Forest Mousse' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Tall heavy stockpot; rolling boil for hours (unlike every other stock); skimmer; blender for emulsifying finish', chef_notes = 'Tonkotsu breaks stock rules on purpose — a hard, rolling boil for 8-12 h emulsifies collagen and fat into the milky body. Top up water; never let bones breach the surface. The first hour''s scum purge decides the cleanliness.', storage = 'Refrigerated 4 days (sets to a firm jelly — correct) / frozen 3 months.', shelf_life = '4 days refrigerated / 3 months frozen.', plating_suggestions = 'Component — combined with tare and aroma oil at the bowl; the opaque ivory pour is the proof of the boil.' where created_by is null and title = 'Tonkotsu Ramen Broth' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Sharp knife for a fine, even brunoise; gloves unless you like pink hands', chef_notes = 'Cut, don''t process — the machine bleeds the beets and turns salsa to purée. Dress at least 30 minutes ahead so the acid rounds the earthiness, but add fresh herbs only at service.', storage = 'Keeps refrigerated, airtight, up to 4 days; drain excess liquid before serving day two onward.', shelf_life = '4 days refrigerated; herbs added fresh each service.', plating_suggestions = 'Spoon alongside rich or fatty items — the magenta pop and acidity are the counterweight; keep it in a tight line or quenelle, it stains everything it touches.' where created_by is null and title = 'Beetroot Salsa' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Templates and sharp knife for panels; piping bag with royal icing or tempered chocolate ''mortar''', chef_notes = 'Bake panels a shade darker than for eating cookies — structure needs the strength. Cool completely flat under light weight so walls don''t bow, and assemble with tempered chocolate; it sets in seconds where icing takes hours.', storage = 'Assembled house keeps at cool room temperature, dry, up to 2 weeks as display.', shelf_life = 'Structural/display: 2 weeks. As served dessert: panels best within 4 days.', plating_suggestions = 'Showpiece — dust ''snow'' only on horizontal surfaces the way it actually falls, and light it from one side on the display table.' where created_by is null and title = 'Chocolate Cookie House' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Heatproof bowl over simmering water or heavy pot; whisk; fine sieve; thermometer', chef_notes = 'Cook to 82°C whisking constantly, then mount the cold butter off the heat — that''s where the shine comes from. Real yuzu juice is intense; taste before adding the full amount and balance with a little lemon if needed.', storage = 'Refrigerated, film pressed to the surface, up to 1 week; freezes up to 1 month.', shelf_life = '7 days refrigerated / 1 month frozen.', plating_suggestions = 'Component recipe — pipe into tart shells, dot between meringue, or quenelle beside dark chocolate; its sharpness earns its place next to rich elements.' where created_by is null and title = 'Yuzu Curd' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Heavy earthenware or cast-iron pot; ladle for the crust ritual', chef_notes = 'Break the crust and baste it back at least twice during the final bake — every crust folded in is a layer of flavour. Beans must be fully tender before assembly; they will not soften further in the acidic, fatty stew.', storage = 'Improves overnight; keeps refrigerated up to 4 days. Reheat slowly, adding stock as the beans keep drinking.', shelf_life = '4 days refrigerated / 3 months frozen (without the duck skin, which never recovers).', plating_suggestions = 'Serve in the pot or a deep bowl, duck confit half-buried, crust intact until it reaches the table — this dish should never look composed.' where created_by is null and title = 'Cassoulet' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Makisu wrapped in cling film; wet hands; sharp wet knife', chef_notes = 'Rice pressed thin and even on the outside, filling centred, and the mat does the shaping — squeeze to hold, not to compress. Sesame or tobiko on the outside hides sins; even rice thickness reveals skill anyway.', storage = 'Technique recipe — made to order; holds marginally better than hosomaki but still under an hour.', shelf_life = 'Within 1 hour, cool room, never refrigerated assembled.', plating_suggestions = 'Eight pieces, cut faces up, arranged in a gentle arc or two staggered rows; the exterior coating should be complete and deliberate, not patchy.' where created_by is null and title = 'Uramaki — Inside-Out Roll Technique' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Pot; fine sieve lined with muslin; no clarification raft needed if steeped, not boiled', chef_notes = 'Steep dried mushrooms below a simmer — boiling extracts bitterness and clouds it. Season at the end with a light hand; concentration sneaks up as it reduces.', storage = 'Refrigerated 4 days; freezes cleanly 2 months.', shelf_life = '4 days refrigerated / 2 months frozen.', plating_suggestions = 'Poured tableside from a small pot over a composed garnish (a few perfect mushroom slices, herbs) — the clarity and aroma are the show.' where created_by is null and title = 'Dried Mushroom Consommé' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Three breading trays; deep pot or fryer; thermometer; rack (never paper)', chef_notes = 'Press the panko on firmly, then rest the breaded cutlet 5 minutes — the coat welds on and won''t slide off in the fryer. Drain on a rack; paper steams the crust from below.', storage = 'Breaded raw cutlets keep refrigerated on a rack, uncovered, up to 12 h — the coat actually improves.', shelf_life = 'Breaded raw: 12 h refrigerated. Fried: serve within minutes.', plating_suggestions = 'Slice in confident strokes and re-assemble slightly fanned so the white interior and golden crust alternate; sauce beside or striped over, never underneath.' where created_by is null and title = 'Katsu — Panko Breading & Frying Technique' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Large pot; skimmer; sieve', chef_notes = 'The broth is the dish — simmer, never boil, and skim early; a cloudy chicken soup is a rushed one. Cook noodles separately and unite in the bowl, or they drink the broth to paste.', storage = 'Broth: refrigerated 4 days / frozen 3 months. Assembled with noodles: eat now.', shelf_life = 'Broth 4 days refrigerated; noodles added per service.', plating_suggestions = 'Generous bowl, vegetables cut evenly enough to show care, herbs at the pass — this dish is judged on honesty, not garnish.' where created_by is null and title = 'Classic Chicken Noodle Soup' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Ice cream machine; blender; fine sieve; thermometer', chef_notes = 'The paste makes or breaks it — pure Sicilian-style pistachio paste, not the sweetened spread. A drop of orange blossom or almond extract can flatter cheap paste, but nothing rescues it. Keep it naturally khaki-green; dyed emerald reads artificial because it is.', storage = 'Churned, -18°C, best within 2 weeks.', shelf_life = '2 weeks frozen at peak.', plating_suggestions = 'Quenelle with crushed salted pistachios pressed onto one face; pairs with cherry, chocolate, or olive oil and flake salt for the confident table.' where created_by is null and title = 'Pistachio Ice Cream' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Thermometer; immersion blender; rack over tray for the pour', chef_notes = 'Same law as every mirror glaze: temperature discipline and zero bubbles. Recover and reuse the tray drippings — strained, they''re good for one more pass.', storage = 'Refrigerated up to 2 weeks; reheat in short bursts, blending between.', shelf_life = '14 days refrigerated.', plating_suggestions = 'Component — glaze frozen, transfer with two offset spatulas after the drip stops; fingerprints are forever, plan the lift before you pour.' where created_by is null and title = 'Glaze (2)' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Small pot; scale; bottle', chef_notes = 'The alternate ratio for larger batches or a softer profile — same discipline as the master ratio: dissolve warm, never boil, and taste against the house reference before it touches rice.', storage = 'Sealed bottle, cool cupboard, 3 months.', shelf_life = '3 months room temperature.', plating_suggestions = 'Component — as with the master ratio: its only stage is the rice itself.' where created_by is null and title = 'Sushi Vinegar (alternate batch)' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Taiyaki mould (fish-shaped iron); ladle with a fine spout', chef_notes = 'Rest the batter 30 minutes and keep it thinner than pancake batter — it must flood the fins and tail of the mould before setting. Fill, add anko, top with more batter, and don''t rush the flip.', storage = 'Batter keeps refrigerated up to 24 hours; whisk before use.', shelf_life = 'Batter: 24 h refrigerated. Cooked taiyaki: eat within the hour — the crisp shell is the point.', plating_suggestions = 'Serve whole and hot, head-on to the guest, paper-wrapped street-style — plating it fancy misses what taiyaki is.' where created_by is null and title = 'Taiyaki Batter' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Hangiri or wide bowl for the rice; sharp yanagiba for slicing; tweezers if the plating goes fine', chef_notes = 'Body-temperature rice, cold fish — the temperature contrast is the dish. Slice each fish across the grain at its own best angle; a chirashi is a portfolio of knife work.', storage = 'Assembly only — components per their own limits; assembled bowl is immediate.', shelf_life = 'Serve within minutes of assembly.', plating_suggestions = 'Arrange by colour like a painter''s palette, each slice overlapping its neighbour just enough; height in the centre, garnish (ikura, shiso, gari) as punctuation, not confetti.' where created_by is null and title = 'Chirashi Bowl — Assembly' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Pot for boiling; scale for portioning filling', chef_notes = 'The filling must be chilled firm before wrapping — soft filling tears the delicate dough. They''re done when they float, plus one more minute; undercooked centres stay gritty.', storage = 'Uncooked, freeze on trays then bag — cook straight from frozen. Never refrigerate raw; they crack.', shelf_life = 'Frozen raw: 2 months. Cooked: serve immediately in their liquid.', plating_suggestions = 'Three in a small bowl with a ladle of the sweet ginger broth they cooked in — the broth is part of the dish, not optional.' where created_by is null and title = 'Tang Yuan (Black Sesame Rice Balls)' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Fine sieve; whisk; heavy-bottomed pot; thermometer', chef_notes = 'Sift the matcha and paste it with a little warm liquid before it meets the custard — dry matcha in hot dairy seizes into bitter flecks. Cook to 82-84°C max; matcha turns muddy and dull past that.', storage = 'Keeps refrigerated, film pressed to surface, up to 3 days. Colour fades with light — store covered and dark.', shelf_life = '3 days refrigerated; the vivid green is best in the first 24 hours.', plating_suggestions = 'Component recipe — use where the green can contrast: over dark chocolate soil, under white meringue, in glass verrines.' where created_by is null and title = 'Matcha Custard Base' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Rice cooker or donabe; hangiri (wooden tub); rice paddle; fan', chef_notes = 'Cut the vinegar in with slicing strokes while fanning — stirring crushes grains, no fanning makes gummy shari. Body temperature at service, never refrigerated; a sushi kitchen''s rice schedule is its heartbeat.', storage = 'Held at room temperature under damp cloth, used within 4 hours of seasoning.', shelf_life = '4 hours from seasoning; never refrigerated.', plating_suggestions = 'Component — every piece of sushi is judged first on the rice; glossy separate grains that hold and release are the standard.' where created_by is null and title = 'Sushi Rice (Shari)' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Small pot; whisk; jar', chef_notes = 'Tamarind, palm sugar, fish sauce — the triangle must balance at ''almost too much of each''. Dissolve the palm sugar fully; undissolved sugar burns in the wok before the noodles finish.', storage = 'Refrigerated, airtight, 1 month — it''s essentially a syrup.', shelf_life = '1 month refrigerated.', plating_suggestions = 'Component — added by ladle to a screaming wok; the sauce should caramelise onto the noodles, never pool beneath them.' where created_by is null and title = 'Pad Thai Sauce' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Wide heavy pan; patience; spatula', chef_notes = 'Real caramelization is 40+ minutes — anything faster is fried onion with sugar. The Asian accent (soy, star anise) goes in at the end, over the finished sweetness, not boiled through it.', storage = 'Refrigerated, airtight, 1 week; freezes in portions 2 months.', shelf_life = '7 days refrigerated / 2 months frozen.', plating_suggestions = 'Component — the umami-sweet base under pork belly, in bao, or folded through mash; a small warm spoonful, glossy, never a cold clump.' where created_by is null and title = 'Karamelizovaná Cibuľa (Caramelized Onion, Asian-Style)' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Wide heavy braising pot; butcher''s twine around each shank; microplane for gremolata', chef_notes = 'Tie each shank or the meat falls off mid-braise and you plate a stew. The marrow is the prize — keep shanks level while cooking so it stays in the bone. Gremolata is made in the final five minutes, never ahead.', storage = 'Improves overnight in its braise; keeps refrigerated 3 days.', shelf_life = '3 days refrigerated / 2 months frozen in braising liquid.', plating_suggestions = 'One shank, bone upright, on saffron risotto alla milanese; gremolata scattered at the pass, marrow spoon on the plate — the guest should be told to dig.' where created_by is null and title = 'Osso Buco alla Milanese' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Dutch oven with lid (the enclosed steam is what replaces kneading and gives the open crumb/crackly crust)', chef_notes = 'The long, slow ferment (12+ hours) is doing the work that kneading would normally do -- do not rush this by using more yeast or a warmer spot, which trades away the flavour and crumb structure that is the whole point of the method. Preheat the Dutch oven itself, not just the oven, before the dough goes in -- a cold pot loses the initial oven-spring.', storage = 'Best within a day of baking; store cut-side down on a board rather than in plastic.', shelf_life = '1-2 days at room temperature; the crust softens faster than a classic baguette since the crumb is wetter.', plating_suggestions = 'The irregular, large-holed crumb is the intended result of minimal handling -- don''t judge it against a tighter sandwich-loaf crumb.' where created_by is null and title = 'No-Knead Rustic Bread' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Blender for the purée; sieve; stand mixer; moulds', chef_notes = 'Pear is delicate — reduce the purée to concentrate flavour before building the mousse, and lift it with a squeeze of lemon and a drop of pear brandy if the house allows. Bloom the gelatine properly; pear''s enzymes punish shortcuts.', storage = 'Set: refrigerated 2 days; in moulds frozen 2 weeks for glazing.', shelf_life = '2 days refrigerated / 2 weeks frozen.', plating_suggestions = 'Its subtlety wants quiet company — vanilla, caramel, a little crumble; a fan of raw ripe pear brushed with syrup on top signals the flavour honestly.' where created_by is null and title = 'Pear Mousse' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Station setup: makisu, tezu bowl, wiping cloths, yanagiba, cutting board at correct height', chef_notes = 'The reference card for the station: rice schedule, tezu ratio, knife-wiping discipline, and the order of service. A clean, quiet station makes clean, quiet sushi — mise en place is the first ingredient.', storage = 'Reference recipe — see component recipes for individual holding times.', shelf_life = '—', plating_suggestions = 'Reference — the standard applies before plating begins: board wiped between fish, knife wet, hands cool.' where created_by is null and title = 'Sushi Station Basics' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Pot for dashi; fine sieve or miso strainer; whisk', chef_notes = 'Miso is whisked in off the heat and the soup never boils again — boiled miso loses its aroma in seconds. Blend miso varieties (white for sweetness, red for depth) to the house profile.', storage = 'Dashi base: 2 days refrigerated. Add miso per service, not ahead.', shelf_life = 'Assembled: serve within the hour. Dashi: 48 h refrigerated.', plating_suggestions = 'Small lacquer-style bowl, tofu and wakame arranged before the pour, scallion on the surface — the cloud of miso swirling as it settles is part of the service.' where created_by is null and title = 'Miso Soup Base' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Whisk and bowl — nothing more; mortar if pounding fresh chilli and garlic', chef_notes = 'Balance to taste every single time — limes vary wildly. The classic test: it should taste almost too strong on a spoon, because it''s built to season plain rice, herbs and grilled meat, not to be sipped.', storage = 'Base (no fresh garlic/chilli) keeps refrigerated 2 weeks; with fresh aromatics, 3-4 days.', shelf_life = '14 days refrigerated as base; 3-4 days once garlic and chilli are in.', plating_suggestions = 'Serve in a small deep bowl per guest with the chilli and garlic floating visibly on top — that''s the sign it''s fresh-made.' where created_by is null and title = 'Nuoc Cham (Vietnamese Dipping Sauce)' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Pot; pestle for bruising aromatics; ladle', chef_notes = 'Bruise, don''t chop, the lemongrass and galangal — they perfume the broth and stay out of the spoon. Lime juice and fish sauce go in OFF the heat; boiling lime turns it bitter and flat.', storage = 'Broth base: refrigerated 2 days. Prawns cooked per service in the broth.', shelf_life = '48 hours refrigerated (base); assembled immediately.', plating_suggestions = 'Serve with the aromatics left dramatically in the bowl (inedible, present), prawns just curled, a last squeeze of lime at the pass — steam should carry the lemongrass ahead of the spoon.' where created_by is null and title = 'Tom Yum Goong (Prawn & Lemongrass Soup)' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Stand mixer with dough hook; steamer with parchment liners; rolling pin', chef_notes = 'Knead until genuinely smooth — the glossy white surface of a good bao is earned in the kneading. Steam over gentle, steady heat; violent boil = wrinkled, collapsed buns. Rest shaped buns until visibly puffy before steaming.', storage = 'Steamed buns freeze superbly up to 2 months; re-steam from frozen 5-6 minutes.', shelf_life = 'Fresh: same day. Frozen steamed: 2 months.', plating_suggestions = 'Component recipe — serve folded bao open with the filling proud at the lip; stack plain buns in the steamer basket they cooked in.' where created_by is null and title = 'Steamed Bao Dough' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Roasting tray; marrow spoons or narrow teaspoons; grill for the bread', chef_notes = 'Soak the split bones in salted water a few hours to purge blood. Roast hot and short — the marrow should quiver, not liquefy into the tray. Salt flake at the end, generously.', storage = 'Raw split bones keep refrigerated in brine 24 h. Roast to order.', shelf_life = 'Roast and serve immediately; there is no acceptable leftover marrow.', plating_suggestions = 'Bones cut-side up on a board, gremolata in a sharp green line along each, charred sourdough leaning against them — rustic on purpose, with good salt visible.' where created_by is null and title = 'Roasted Bone Marrow with Herb Gremolata' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Roasting rack (meat must hang or sit above the tray); basting brush; thermometer', chef_notes = 'Marinate at least overnight and reserve some marinade uncontaminated for glazing. The signature char comes from repeated glaze-and-return passes at high heat at the end — expect and want the edges nearly blackened.', storage = 'Keeps refrigerated, wrapped, up to 4 days; slices reheat well in a hot pan, cut sides down, to re-caramelise.', shelf_life = '4 days refrigerated / 2 months frozen, sliced with glaze.', plating_suggestions = 'Glossy slices on the bias over rice or noodles, spooned with warmed reserved glaze; the lacquered red-brown edge should face the guest.' where created_by is null and title = 'Char Siu Pork Belly' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Two pots (broth and wonton water — always separate); wide skimmer', chef_notes = 'Boil wontons in water, serve in broth — boiling them in the broth clouds it with starch. The broth should be clean and light; the wonton is the star, the soup is its stage.', storage = 'Broth 4 days refrigerated; wontons frozen raw 2 months, cooked to order.', shelf_life = 'Assembled: immediately. Components: as noted.', plating_suggestions = 'Five or six wontons, pleats up, in a shallow pool of clear broth, greens and a thread of sesame oil — restraint reads as confidence.' where created_by is null and title = 'Wonton Soup' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'High-sided cake tin; parchment left rough and tall; very hot oven', chef_notes = 'The burn is the recipe — trust the near-black top and the earthquake wobble at the centre when you pull it. It sets as it cools; refrigerating it too soon steals the custardy middle.', storage = 'Room temperature the first day is the best version; refrigerated up to 3 days after.', shelf_life = '3 days refrigerated; bring slices back toward room temp before serving.', plating_suggestions = 'Serve in generous rustic wedges with the pleated parchment ghost visible on the sides — no glaze, no fruit needed; a pour of cream at most.' where created_by is null and title = 'Burnt Basque Cheesecake' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Smoker; probe thermometer; butcher paper; long serrated or granton slicer; towel-lined cooler for the rest', chef_notes = 'The rest is a cooking stage: a minimum 1-2 h wrapped in a warm cooler transforms the texture. Slice against the grain — and note the grain flips between flat and point. Slices should bend, not break.', storage = 'Whole rested brisket holds warm 4+ h wrapped; sliced, it dries in minutes — slice only at the pass.', shelf_life = 'Cooked whole: 4 days refrigerated / 3 months frozen. Sliced: serve immediately.', plating_suggestions = 'Thick pencil-width slices with the smoke ring facing up and out; bark visible, no sauce on top — a pot of house sauce on the side states confidence.' where created_by is null and title = 'Smoked Beef Brisket' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Spice grinder for whole spices; airtight jar; scale for ratios', chef_notes = 'Grind whole spices fresh where the recipe allows — pre-ground cumin and coriander fade in weeks. Salt is in the rub: don''t season the meat separately or you''ll double it.', storage = 'Airtight, dark, room temperature — up to 2 months at full strength.', shelf_life = '2 months for peak aroma; usable longer but fading.', plating_suggestions = 'Component recipe — apply generously enough to form bark; a light extra dusting on the sliced meat at the pass wakes the aroma back up.' where created_by is null and title = 'House BBQ Dry Rub' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Oven tray; parchment; food processor or fingertips', chef_notes = 'Kinako burns before ordinary crumble colours — bake lower and pull at pale gold; it deepens on the tray. The roasted-soy nuttiness reads almost like peanut against dairy desserts.', storage = 'Airtight at room temperature 1 week; re-crisp 5 minutes at 140°C if softened.', shelf_life = '7 days airtight.', plating_suggestions = 'Component — the textural floor: spoon a tight line and seat the quenelle or mousse on it so it stays crunchy to the last bite.' where created_by is null and title = 'Kinako Crumble' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Pot for the lobster; split-top brioche rolls; griddle for buttering the roll', chef_notes = 'The roll is toasted in butter on its flat sides — that''s the whole trick. Dress the lobster lightly and keep it cold; the warm-butter version is Connecticut style, pick a lane and commit.', storage = 'Picked dressed lobster: refrigerated, up to 24 h. Assemble strictly to order.', shelf_life = 'Lobster salad: 24 h refrigerated. Assembled roll: immediately.', plating_suggestions = 'Overfill visibly — the lobster should stand taller than the bread; chives, a lemon cheek, salted crisps beside, nothing else.' where created_by is null and title = 'New England-Style Lobster Roll' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Immersion circulator; vacuum sealer; blast chiller or ice bath for anything held', chef_notes = 'Reference sheet — the two rules that save every service: chill fast (ice bath, fully cold before storing) if not serving immediately, and always finish with a hard, short sear; sous-vide without a sear is hospital food.', storage = 'Cooked-chilled bags: refrigerated 5-7 days unopened (proper chill assumed), labeled with cook date.', shelf_life = '5-7 days refrigerated in unopened bags; once opened and seared, serve.', plating_suggestions = 'Component reference — whatever the cut, slice to show the edge-to-edge even doneness; that gradient-free interior is the whole argument for the technique.' where created_by is null and title = 'Sous-Vide Cuts Reference' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Makiyakinabe (rectangular tamago pan); chopsticks; oil-soaked cloth pad', chef_notes = 'Layer by thin layer, rolling each while barely set — the cut face should show fine, even strata. Dashi in the egg makes it tremble; sugar content decides the browning speed, so adjust the flame, not the recipe.', storage = 'Wrapped, refrigerated, 2 days — some houses serve it slightly chilled on purpose.', shelf_life = '48 hours refrigerated.', plating_suggestions = 'A thick slice with the layered cross-section facing up, alone or as the traditional last course of a sushi service — some say the tamago is how you judge the chef.' where created_by is null and title = 'Tamagoyaki (Sweet Rolled Omelette)' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Dry pan for toasting; spice grinder; airtight jar', chef_notes = 'Toast whole spices separately — they finish at different speeds — then grind together. The aroma when the jar opens is your freshness gauge; when it whispers, remake it.', storage = 'Airtight, dark, room temperature, 6 weeks at full strength.', shelf_life = '6 weeks peak; usable to 3 months.', plating_suggestions = 'Component — bloom in fat at the start of cooking, never sprinkle raw at the end; a pinch over finished dishes only if freshly toasted.' where created_by is null and title = 'Curry Spice Mix' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Deep heavy pot or sous-vide setup; enough fat to submerge; storage crock or vac bags', chef_notes = 'Cure 12-24 h, rinse, dry, then cook submerged at a bare murmur (85-90°C) until the meat gives at the bone. The confit itself is a preservation method — done right, flavour improves over days under fat.', storage = 'Under its fat, refrigerated, up to 1 month — the traditional way. Vac-packed: same.', shelf_life = '1 month refrigerated under fat. Once crisped: serve immediately.', plating_suggestions = 'Crisp skin-side down in a dry pan until it crackles, serve skin up — over lentils, cassoulet, or bitter leaves; the skin must sound crisp when tapped with a fork.' where created_by is null and title = 'Duck Leg Confit' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Small pot; whisk; jar', chef_notes = 'House teriyaki is reduced to a light syrup, not thickened with starch — the shine must come from sugar and reduction. Mirin quality is audible in the result.', storage = 'Refrigerated, airtight, 1 month.', shelf_life = '1 month refrigerated.', plating_suggestions = 'Component — brush in layers over grilling proteins; a final pass off the heat gives the mirror gloss the name promises.' where created_by is null and title = 'Teriyaki Sauce' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Wok or heavy pot; ladle; rice service alongside', chef_notes = 'Fry the paste in cracked coconut cream until the oil stains red and separates — stop too early and the curry tastes raw forever. Season in the Thai order: fish sauce, palm sugar, then aromatics off the heat.', storage = 'Sauce: refrigerated 3 days / frozen 1 month. Assembled with vegetables: same service.', shelf_life = '3 days refrigerated (sauce) / 1 month frozen.', plating_suggestions = 'The red-stained oil pooling at the rim is authenticity, not grease — don''t skim it; basil and sliced red chilli at the pass.' where created_by is null and title = 'Thai Red Curry' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Ice cream machine; fine sieve; whisk', chef_notes = 'Paste the matcha with warm base before combining, and keep the cook gentle — matcha scorched past 85°C goes bitter and khaki. Slight over-seasoning with salt lifts the green notes.', storage = 'Churned, at -18°C, best within 2 weeks.', shelf_life = '2 weeks frozen for colour and aroma; safe longer.', plating_suggestions = 'Quenelle against something dark or neutral — chocolate soil, black sesame — the green must stay saturated; dust a whisper of fresh matcha at the pass.' where created_by is null and title = 'Green Tea Ice Cream' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Thermometer (non-negotiable); immersion blender; tall jug; sieve', chef_notes = 'Use at the stated temperature to the degree — too warm melts the mousse''s surface, too cool ropes and drags. Blend without lifting the head; every bubble becomes a crater on the finished piece.', storage = 'Refrigerated up to 2 weeks; re-warm gently and re-blend before each use.', shelf_life = '14 days refrigerated, reheated properly.', plating_suggestions = 'Component — pour in one continuous confident pass over frozen pieces on a rack; colours well, so it''s the base for the house''s tinted mirror finishes.' where created_by is null and title = 'Glaze (1) — White Chocolate/Cocoa Butter' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Heavy small pot; thermometer; heatproof jar; fine sieve optional', chef_notes = 'Pour the oil over the aromatics at the right temperature — too hot scorches to acrid, too cool leaves it raw. The sediment is the treasure; never strain it all away.', storage = 'Sealed jar, cool and dark, 1 month; refrigeration extends but dulls aroma slightly.', shelf_life = '1 month at cool room temp / 2 months refrigerated.', plating_suggestions = 'Component — spoon with intent so the red oil and dark sediment both land; a ring of rāyu around dumplings does more than any garnish.' where created_by is null and title = 'Chilli Oil (Rāyu)' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Thermometer; immersion blender; sieve; shallow container', chef_notes = 'Anglaise to 82-84°C, butter mounted at 40°C — the order and temperatures are the recipe. Yuzu sharpness carries: taste before the last addition of juice.', storage = 'Refrigerated, film on surface, 3 days.', shelf_life = '3 days refrigerated.', plating_suggestions = 'Component — pipe where its sunshine acidity cuts richness: beside dark chocolate, inside choux, or dotted through a coconut dessert.' where created_by is null and title = 'Yuzu Crémeux' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Microwave or steamer; ample cornstarch/katakuriko for dusting; dough scraper', chef_notes = 'Work fast and hot — gyūhi is only pliable while warm. Dust hands and bench heavily; the moment it sticks, it tears. Cook in short bursts, stirring between, until translucent and glossy.', storage = 'Wrapped airtight at room temperature up to 2 days — refrigeration turns it chalky and hard.', shelf_life = '2 days at room temp; filled mochi with fresh cream or fruit: same day, refrigerated, eaten within 24 h.', plating_suggestions = 'Component recipe — wrap ice cream, ganache or fruit; keep the seam underneath and dust off excess starch before it reaches the plate.' where created_by is null and title = 'Mochi Dough (Gyūhei)' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Heavy pot; food processor or masher for koshian; fine sieve if going smooth', chef_notes = 'Two boils: discard the first water to shed astringency, then simmer until a bean crushes between two fingers with no resistance before any sugar goes in — sugar added early locks beans hard forever.', storage = 'Refrigerated, airtight, up to 1 week; freezes beautifully in flat portions up to 3 months.', shelf_life = '7 days refrigerated / 3 months frozen.', plating_suggestions = 'Component recipe — the backbone of dorayaki, taiyaki, dango and mochi; keep it glossy and spoonable, loosened with a little water if it tightens in the fridge.' where created_by is null and title = 'Red Bean Paste (Anko)' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Shallow brûlée dishes; water bath; blowtorch; fine sieve', chef_notes = 'Bake low in a water bath to the barest tremble — overbaked brûlée is scrambled custard with sugar on top. Torch the sugar in two thin coats rather than one thick one; it caramelises evenly and stays glass-thin.', storage = 'Baked custards keep refrigerated 3 days; torch strictly at service.', shelf_life = 'Custard: 3 days refrigerated. Torched: the crack lasts 20 minutes, serve at once.', plating_suggestions = 'The dish is the plate; serve with the sugar still faintly warm so the first spoon gets the crack-and-quiver contrast. Real vanilla seeds should speckle the custard visibly.' where created_by is null and title = 'Classic Vanilla Crème Brûlée' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Heavy pan or plancha at full heat; timer counted in seconds; sharp slicer', chef_notes = 'Wagyu of this grade is cooked in seconds and seasoned in grains — the marbling does everything else. Room-temperature meat, screaming surface, and a rest almost as long as the cook.', storage = 'Vacuum-sealed raw, refrigerated, per supplier''s dating; portion cut only on the day of service.', shelf_life = 'Per supplier vacuum date raw; cooked — immediately, always.', plating_suggestions = 'Thin slices, barely kissed with salt or nikiri, served alone — anything else on the plate is a distraction the beef didn''t ask for.' where created_by is null and title = 'Kobe Kagoshima' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Whisk or jar with tight lid; microplane for the garlic', chef_notes = 'Let it sit 30 minutes so the dried herbs wake up in the vinegar, and shake hard before every use — a proper Italian dressing is a temporary truce, not an emulsion.', storage = 'Refrigerated, sealed jar, up to 1 week.', shelf_life = '7 days refrigerated.', plating_suggestions = 'Toss with sturdy leaves and let some pool at the bowl''s base for bread; also earns its keep as a quick marinade for grilled vegetables.' where created_by is null and title = 'Italian Dressing' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Stand mixer with dough hook (butter this rich needs machinery); loaf tins or moulds; egg-wash brush', chef_notes = 'Cold butter added in stages to a developed dough, then a long cold proof — brioche rewards patience twice. The windowpane test matters more here than in any lean bread.', storage = 'Baked: wrapped at room temperature 2 days; frozen 1 month. Dough: refrigerated overnight is part of the method.', shelf_life = '2 days room temp / 1 month frozen; day-two brioche is French toast destiny.', plating_suggestions = 'Serve in thick golden slices with the shreddable crumb visible; the deep-brown glossy crust from a double egg wash is the signature.' where created_by is null and title = 'Brioche Recipe' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Roasting tray for the rhubarb; ice cream machine; blender', chef_notes = 'Roast, don''t stew, the rhubarb — concentration and a little caramelised edge keep the flavour from washing out in the cream. Save the roasting syrup for ripple.', storage = 'Churned, -18°C, best within 2 weeks.', shelf_life = '2 weeks frozen at peak.', plating_suggestions = 'Quenelle with the pink ripple showing, a piece of crisp (ginger crumble, shortbread) beside — rhubarb''s blush deserves to be seen.' where created_by is null and title = 'Rhubarb Ice Cream' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Small heavy pot; strainer; brush', chef_notes = 'Reduce gently to a light syrup — it thickens more as it cools, and over-reduction makes it tar. Traditionally enriched with eel bones when available; the depth is noticeable.', storage = 'Refrigerated, sealed, 1 month.', shelf_life = '1 month refrigerated.', plating_suggestions = 'Brushed over grilled eel or drizzled in fine lines across sushi and donburi — its lacquered sheen is the finishing stroke.' where created_by is null and title = 'Unagi Sauce (Eel Sauce)' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Bowl for cold steeping; fine strainer; bottle', chef_notes = 'Steep the citrus and katsuobushi cold, never heat it — ponzu''s whole identity is a fresh citrus top note over soy depth. Strain after 24 h; longer turns it bitter.', storage = 'Refrigerated, sealed, 3 weeks.', shelf_life = '21 days refrigerated; brightest the first week.', plating_suggestions = 'Pool beneath tataki, crudo or dumplings at the last moment; it''s a sauce for cold and barely-warm dishes — heat kills it.' where created_by is null and title = 'Ponzu Sauce' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Small pot (warm only to dissolve); scale; bottle', chef_notes = 'Warm just enough to dissolve sugar and salt — boiling drives off the vinegar''s aroma. Taste against the house master ratio before it goes anywhere near rice.', storage = 'Sealed bottle, cool cupboard, 3 months.', shelf_life = '3 months room temperature.', plating_suggestions = 'Component — folded into warm rice with cutting strokes; judged entirely by the sheen and seasoning of the finished shari.' where created_by is null and title = 'Sushi Vinegar (Sushi Ocot)' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Molcajete or fork and bowl — never a blender; sharp knife', chef_notes = 'Mash coarse and season in layers — lime and salt first into the onion-chilli base, then the avocado folded through. Smooth guacamole is baby food; texture is the dish.', storage = 'Surface pressed with film plus a squeeze of lime, refrigerated, 24 h at most.', shelf_life = 'Same day is honest; 24 h refrigerated maximum.', plating_suggestions = 'Serve in a rough mound, never smoothed flat, with visible avocado pieces; warm totopos beside and a little diced tomato and coriander on top, added last.' where created_by is null and title = 'Guacamole' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Cake tin; small pot for soaking the dates; skewer for the pour-over stage', chef_notes = 'Soak the dates in hot liquid with the bicarb — that''s what melts them into the crumb. Poke and soak with sauce while warm; a dry date cake is a missed opportunity for toffee.', storage = 'Wrapped, room temperature 2 days, refrigerated 5; improves on day one''s evening.', shelf_life = '2 days room temp / 5 days refrigerated / 2 months frozen.', plating_suggestions = 'Serve warm with the toffee sauce poured at the table and something cold against it — crème fraîche or vanilla ice cream doing the melting.' where created_by is null and title = 'Date Cake' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Springform or rings; fine sieve for the matcha; water bath if baked', chef_notes = 'Matcha and yuzu pull opposite directions — keep the matcha in the body and the yuzu as a sharp top layer or curd so each stays distinct instead of muddying together.', storage = 'Refrigerated, covered, 3 days.', shelf_life = '3 days refrigerated; colour brightest first 24 h.', plating_suggestions = 'Clean-cut slice showing the green-gold layers, a few yuzu jelly cubes and a dust of matcha beside — the two-tone face is the plate.' where created_by is null and title = 'Matcha-Yuzu Cheesecake' and coalesce(chef_notes,'') = '';
update recipes set equipment = 'Steamer with parchment liners; rolling pin; scale for even portioning', chef_notes = 'Even portioning and a gentle, steady steam are the difference between a basket of clouds and a basket of golf balls. Rest shaped buns until visibly puffy before they see steam.', storage = 'Steamed: frozen 2 months, re-steamed from frozen 5-6 minutes — better than day-two refrigerated.', shelf_life = 'Fresh: same day. Frozen: 2 months.', plating_suggestions = 'Serve in the steamer basket, lid lifted at the table for the cloud of steam; folded bao get their filling showing proudly at the lip.' where created_by is null and title = 'Steamed Buns' and coalesce(chef_notes,'') = '';

-- Green gazpacho joined the library after the 14.7. export, so it wasn't in the generated set —
-- authored and applied separately the same day.
update recipes set equipment = 'High-speed blender; fine sieve; chilled bowls', chef_notes = 'Blend with plenty of ice-cold water and strain fine — the silkiness is what separates a green gazpacho from a smoothie. Season cold and boldly; chilling mutes both salt and acid, so adjust after refrigeration, not before.', storage = 'Refrigerated, covered, 2 days — the green dulls and the fresh herb aroma fades after that.', shelf_life = '48 hours refrigerated; colour and aroma brightest the first day.', plating_suggestions = 'Ice-cold bowls, a thread of good olive oil and a few contrasting garnish points (almond, grape, cucumber dice) — or pour tableside over the garnish for service theatre.' where created_by is null and title = 'Green gazpacho' and coalesce(chef_notes,'') = '';

